export function generateBulkQuestions(): CamrtQuestion[] {
  const qs: CamrtQuestion[] = [];

  // Systematic question generation per body part and category
  const bodyPartQuestions: CamrtQuestion[] = [
    // CHEST
    { question: "On a PA chest radiograph, which side of the heart is normally the most prominent?", optionA: "Right side", optionB: "Left side (left ventricle)", optionC: "Both sides equally", optionD: "Neither side", correctAnswer: "B", rationale: "The left ventricle forms the left heart border and is the most prominent chamber seen on PA chest. Right heart border is formed by the right atrium.", modality: "X-ray", bodyPart: "Chest", category: "Image Evaluation", difficulty: 1, topic: "Image Critique" },
    { question: "The PA chest radiograph is preferred over AP because:", optionA: "It uses less radiation", optionB: "It minimizes cardiac magnification since the heart is closer to the image receptor", optionC: "It shows more lung detail", optionD: "It requires less exposure time", correctAnswer: "B", rationale: "In PA projection, the heart (anterior structure) is closer to the IR, reducing magnification. In AP, the heart is farther from the IR, causing significant magnification and size distortion.", modality: "X-ray", bodyPart: "Chest", category: "Radiographic Procedures", difficulty: 1, topic: "Chest Radiography" },
    { question: "The costophrenic angles on a properly positioned PA chest should be:", optionA: "Obscured by the diaphragm", optionB: "Sharp and clear, without blunting", optionC: "Filled with fluid", optionD: "Clipped off the image", correctAnswer: "B", rationale: "The costophrenic angles should be sharp and clear on a normal chest radiograph. Blunting suggests pleural effusion, with approximately 200-300 mL required for visible blunting on upright PA.", modality: "X-ray", bodyPart: "Chest", category: "Image Evaluation", difficulty: 2, topic: "Image Critique" },
    { question: "For a chest radiograph on a patient who cannot stand, the best alternative is:", optionA: "Supine AP", optionB: "AP upright (sitting on a stretcher or bed)", optionC: "Prone", optionD: "Lateral only", correctAnswer: "B", rationale: "If the patient cannot stand, AP upright is preferred over supine because it still allows detection of air-fluid levels, demonstrates the diaphragm position accurately, and reduces engorgement of pulmonary vessels.", modality: "X-ray", bodyPart: "Chest", category: "Radiographic Procedures", difficulty: 1, topic: "Chest Radiography" },
    { question: "A portable AP chest radiograph appears darker on one side. This is most likely caused by:", optionA: "The patient's pathology", optionB: "Patient rotation causing one lung to appear more radiolucent than the other", optionC: "Overexposure", optionD: "Underexposure", correctAnswer: "B", rationale: "Asymmetric lung density on AP chest is commonly caused by patient rotation. The side rotated farther from the IR appears more lucent, while the closer side appears denser. Check clavicle and spinous process alignment.", modality: "X-ray", bodyPart: "Chest", category: "Image Evaluation", difficulty: 2, topic: "Image Critique" },
    { question: "The trachea on a normal PA chest should be:", optionA: "Deviated to the right", optionB: "Midline or slightly deviated to the right at the level of the aortic knob", optionC: "Deviated to the left", optionD: "Not visible", correctAnswer: "B", rationale: "The trachea is normally midline with a slight deviation to the right at the level of the aortic knob due to the aortic arch passing to the left. Significant tracheal deviation may indicate mass, effusion, or pneumothorax.", modality: "X-ray", bodyPart: "Chest", category: "Image Evaluation", difficulty: 2, topic: "Image Critique" },

    // HAND/WRIST
    { question: "The PA projection of the hand requires:", optionA: "Hand pronated (palm down) with fingers together", optionB: "Hand pronated (palm down) with fingers slightly separated", optionC: "Hand supinated (palm up)", optionD: "Hand in lateral position", correctAnswer: "B", rationale: "PA hand requires the palm flat on the IR (pronated) with fingers slightly separated to prevent overlap. This demonstrates all phalanges, metacarpals, and carpals with open interphalangeal joints.", modality: "X-ray", bodyPart: "Hand", category: "Radiographic Procedures", difficulty: 1, topic: "Upper Extremity" },
    { question: "The scaphoid (navicular) bone is best demonstrated on:", optionA: "PA wrist in neutral", optionB: "PA wrist with ulnar deviation and slight elevation", optionC: "AP wrist", optionD: "Lateral wrist", correctAnswer: "B", rationale: "Ulnar deviation elongates and opens the scaphoid by aligning it more parallel to the IR. Elevation on the radial side (scaphoid view) further reduces foreshortening.", modality: "X-ray", bodyPart: "Wrist", category: "Radiographic Procedures", difficulty: 2, topic: "Upper Extremity" },
    { question: "On a lateral wrist radiograph, the alignment of the lunate should show:", optionA: "Complete dislocation", optionB: "The lunate cupping the capitate, with the radius, lunate, and capitate forming a straight line", optionC: "The lunate rotated 90 degrees", optionD: "No specific relationship", correctAnswer: "B", rationale: "On a normal lateral wrist, the radius, lunate, and capitate should form a straight line (collinear alignment). The lunate should cup the capitate. Disruption indicates carpal instability or dislocation.", modality: "X-ray", bodyPart: "Wrist", category: "Image Evaluation", difficulty: 3, topic: "Image Critique" },
    { question: "A ball-catcher's view (Norgaard projection) of the hands is used to evaluate:", optionA: "Scaphoid fractures", optionB: "Early erosive changes of rheumatoid arthritis in the MCP and PIP joints", optionC: "Carpal tunnel syndrome", optionD: "Finger dislocations", correctAnswer: "B", rationale: "The Norgaard (ball-catcher's) view places the hands in semi-supinated oblique position, demonstrating the radial aspects of the MCP and PIP joints where early rheumatoid erosions typically begin.", modality: "X-ray", bodyPart: "Hand", category: "Radiographic Procedures", difficulty: 3, topic: "Upper Extremity" },

    // SHOULDER
    { question: "The Y-view (lateral scapula) of the shoulder demonstrates:", optionA: "The AC joint", optionB: "The relationship of the humeral head to the glenoid fossa, forming a Y shape from the scapular body, acromion, and coracoid", optionC: "The clavicle", optionD: "The sternoclavicular joint", correctAnswer: "B", rationale: "The scapular Y view places the patient in a 45-60 degree anterior oblique. The acromion, coracoid, and scapular body form a Y shape with the glenoid at the center. The humeral head should sit at the center of the Y.", modality: "X-ray", bodyPart: "Shoulder", category: "Radiographic Procedures", difficulty: 2, topic: "Upper Extremity" },
    { question: "For an AP clavicle projection, the central ray is directed:", optionA: "30 degrees cephalad", optionB: "Perpendicular to the midshaft of the clavicle", optionC: "15 degrees caudad", optionD: "45 degrees cephalad", correctAnswer: "B", rationale: "The AP clavicle uses a perpendicular central ray directed to the midshaft of the clavicle. For the AP axial clavicle, a 15-30 degree cephalad angle projects the clavicle above the ribs.", modality: "X-ray", bodyPart: "Shoulder", category: "Radiographic Procedures", difficulty: 1, topic: "Upper Extremity" },

    // HIP
    { question: "The Lauenstein method for the hip demonstrates:", optionA: "The femoral shaft", optionB: "A true lateral (frog-leg) view of the hip with the femoral neck in lateral profile", optionC: "The sacroiliac joints", optionD: "The pubic symphysis", correctAnswer: "B", rationale: "The Lauenstein method (frog-leg lateral) demonstrates the femoral neck in lateral profile, the greater and lesser trochanters, and the hip joint. Contraindicated in suspected fracture.", modality: "X-ray", bodyPart: "Hip", category: "Radiographic Procedures", difficulty: 2, topic: "Lower Extremity" },
    { question: "Garden classification is used for:", optionA: "Ankle fractures", optionB: "Femoral neck (subcapital hip) fractures", optionC: "Wrist fractures", optionD: "Vertebral fractures", correctAnswer: "B", rationale: "Garden classification grades femoral neck fractures from I (incomplete/valgus impacted) to IV (complete with displacement). It helps determine treatment — Garden I-II may be pinned; Garden III-IV typically require arthroplasty.", modality: "X-ray", bodyPart: "Hip", category: "Image Evaluation", difficulty: 3, topic: "Pathology" },

    // SPINE
    { question: "The flexion and extension views of the cervical spine are performed to evaluate:", optionA: "Fractures", optionB: "Ligamentous instability and abnormal vertebral motion", optionC: "Disc herniation", optionD: "Spinal cord compression", correctAnswer: "B", rationale: "Flexion-extension lateral C-spine views demonstrate abnormal motion (instability) between vertebrae, indicating ligamentous injury. They should only be performed on alert, cooperative patients after fracture has been excluded.", modality: "X-ray", bodyPart: "Cervical Spine", category: "Radiographic Procedures", difficulty: 2, topic: "Spine Radiography" },
    { question: "On an AP cervical spine, the uncovertebral joints (joints of Luschka) are demonstrated:", optionA: "Never on AP view", optionB: "As small joints at the lateral margins of the cervical vertebral bodies (C3-C7)", optionC: "Only on oblique view", optionD: "Only on lateral view", correctAnswer: "B", rationale: "Uncovertebral joints (joints of Luschka) are seen on AP cervical spine as small notch-like articulations at the lateral margins of the C3-C7 vertebral bodies. Osteophytes here can cause nerve root compression (radiculopathy).", modality: "X-ray", bodyPart: "Cervical Spine", category: "Image Evaluation", difficulty: 3, topic: "Image Critique" },
    { question: "The L5-S1 spot lateral view is performed because:", optionA: "The standard lateral doesn't show L5 well", optionB: "The L5-S1 junction is difficult to penetrate on full lateral view due to the dense iliac crests", optionC: "It reduces patient dose", optionD: "It's faster than a full lateral", correctAnswer: "B", rationale: "A cone-down (spot) lateral of L5-S1 with tight collimation and potentially higher technique allows better visualization of the L5-S1 disc space, which is often obscured by the dense pelvis on the full lateral.", modality: "X-ray", bodyPart: "Lumbar Spine", category: "Radiographic Procedures", difficulty: 2, topic: "Spine Radiography" },
    { question: "The Ferguson method for the AP lumbosacral junction uses:", optionA: "No tube angle", optionB: "30-35 degrees cephalad tube angle to open the L5-S1 joint space", optionC: "15 degrees caudad", optionD: "45 degrees cephalad", correctAnswer: "B", rationale: "The Ferguson method uses 30-35 degrees cephalad tube angle to project the L5-S1 joint space open by paralleling the disc space. The central ray enters at the ASIS level.", modality: "X-ray", bodyPart: "Lumbar Spine", category: "Radiographic Procedures", difficulty: 2, topic: "Spine Radiography" },

    // SKULL/SINUSES
    { question: "The petrous pyramids on a PA skull (0 degrees) fill:", optionA: "The upper half of the orbits", optionB: "The entire orbits", optionC: "Below the orbits", optionD: "The frontal sinuses", correctAnswer: "B", rationale: "On a PA skull with 0-degree tube angle, the petrous ridges fill the orbits completely. With 15-degree caudad (Caldwell), they project to the lower 1/3 of the orbits.", modality: "X-ray", bodyPart: "Skull", category: "Image Evaluation", difficulty: 2, topic: "Image Critique" },
    { question: "For paranasal sinus imaging, the patient must be:", optionA: "Supine", optionB: "Erect to demonstrate air-fluid levels using a horizontal beam", optionC: "Prone", optionD: "In any position", correctAnswer: "B", rationale: "Sinus radiographs must be performed erect with a horizontal x-ray beam to detect air-fluid levels, which indicate sinusitis, hemorrhage, or other pathology. Supine views cannot demonstrate fluid levels.", modality: "X-ray", bodyPart: "Sinuses", category: "Radiographic Procedures", difficulty: 1, topic: "Skull Radiography" },
    { question: "The lateral sinus projection best demonstrates:", optionA: "The maxillary sinuses", optionB: "The sphenoid sinus, sella turcica, and the superimposed frontal sinuses", optionC: "Only the ethmoid sinuses", optionD: "The mastoid air cells", correctAnswer: "B", rationale: "The lateral projection of the sinuses demonstrates the sphenoid sinus (best projection for sphenoid), sella turcica, superimposed frontal sinuses, and overall sinus size.", modality: "X-ray", bodyPart: "Sinuses", category: "Radiographic Procedures", difficulty: 2, topic: "Skull Radiography" },

    // ABDOMEN
    { question: "An acute abdominal series typically includes:", optionA: "Only a supine abdomen", optionB: "Supine AP abdomen, upright AP abdomen, and PA chest", optionC: "Only a CT scan", optionD: "Only an upright abdomen", correctAnswer: "B", rationale: "A standard acute abdominal series includes: 1) supine AP abdomen, 2) upright AP abdomen (for air-fluid levels), and 3) PA chest (for free air under diaphragm). Some protocols substitute left lateral decubitus for upright.", modality: "X-ray", bodyPart: "Abdomen", category: "Radiographic Procedures", difficulty: 2, topic: "Abdominal Radiography" },
    { question: "On a supine abdomen, the psoas muscle shadows are:", optionA: "Never visible", optionB: "Normally visible as bilateral symmetric soft tissue stripes along the lumbar spine", optionC: "Only visible with contrast", optionD: "Always obscured", correctAnswer: "B", rationale: "The psoas muscle shadows are normally visible on abdominal radiographs as symmetric soft tissue stripes along the lumbar spine. Their obliteration (loss of visibility) may indicate retroperitoneal pathology (hemorrhage, abscess, tumor).", modality: "X-ray", bodyPart: "Abdomen", category: "Image Evaluation", difficulty: 2, topic: "Image Critique" },
    { question: "Left lateral decubitus abdomen radiograph is performed to detect:", optionA: "Kidney stones", optionB: "Free intraperitoneal air (pneumoperitoneum) that rises to the non-dependent side", optionC: "Bowel obstruction only", optionD: "Appendicitis", correctAnswer: "B", rationale: "Left lateral decubitus with a horizontal beam shows free air rising between the liver and right abdominal wall (non-dependent side). It is used when the patient cannot stand for upright imaging.", modality: "X-ray", bodyPart: "Abdomen", category: "Radiographic Procedures", difficulty: 2, topic: "Abdominal Radiography" },

    // FOOT/ANKLE
    { question: "The AP oblique (medial rotation) of the ankle demonstrates:", optionA: "The ankle mortise", optionB: "The distal tibiofibular syndesmosis and lateral malleolus free from tibia overlap", optionC: "Only the talus", optionD: "The calcaneus", correctAnswer: "B", rationale: "The AP oblique ankle with 45-degree medial rotation separates the distal tibiofibular syndesmosis and demonstrates the lateral malleolus free from overlap with the tibia.", modality: "X-ray", bodyPart: "Ankle", category: "Radiographic Procedures", difficulty: 2, topic: "Lower Extremity" },
    { question: "The Harris-Beath (ski jumper's) view demonstrates:", optionA: "The ankle joint", optionB: "The posterior facet of the subtalar joint and calcaneus", optionC: "The metatarsals", optionD: "The toes", correctAnswer: "B", rationale: "The Harris-Beath view (axial calcaneus with different angulation) demonstrates the posterior subtalar joint and calcaneal body, used to evaluate calcaneal fractures and subtalar joint pathology.", modality: "X-ray", bodyPart: "Foot", category: "Radiographic Procedures", difficulty: 3, topic: "Lower Extremity" },
    { question: "For a weight-bearing AP foot, the purpose is to:", optionA: "Reduce exposure", optionB: "Demonstrate the true anatomic relationships under physiologic load, assessing arch height and alignment", optionC: "Make the patient more comfortable", optionD: "Speed up the exam", correctAnswer: "B", rationale: "Weight-bearing foot views demonstrate the longitudinal arch under load, true alignment of the metatarsals and tarsals, and are essential for evaluating pes planus (flat foot) and pes cavus.", modality: "X-ray", bodyPart: "Foot", category: "Radiographic Procedures", difficulty: 2, topic: "Lower Extremity" },

    // KNEE
    { question: "The tunnel (intercondylar notch) view of the knee demonstrates:", optionA: "The patella", optionB: "The intercondylar fossa, tibial eminences, and posterior femoral condyles", optionC: "The tibial plateau", optionD: "The fibular head", correctAnswer: "B", rationale: "The tunnel view (Camp-Coventry or Béclère) projects through the intercondylar notch with the knee flexed 40-50 degrees, demonstrating the intercondylar fossa, tibial eminences, and posterior condyles. Useful for loose bodies.", modality: "X-ray", bodyPart: "Knee", category: "Radiographic Procedures", difficulty: 2, topic: "Lower Extremity" },
    { question: "The Merchant (sunrise) view of the patella is performed with:", optionA: "Full extension", optionB: "Both knees flexed 45 degrees over the table edge, beam angled inferosuperiorly through the patellofemoral joints", optionC: "One knee in lateral position", optionD: "No flexion", correctAnswer: "B", rationale: "The Merchant view demonstrates the bilateral patellofemoral joints with knees flexed 45 degrees over the table edge. The central ray is angled 30 degrees from horizontal, directed inferosuperiorly.", modality: "X-ray", bodyPart: "Knee", category: "Radiographic Procedures", difficulty: 2, topic: "Lower Extremity" },

    // EQUIPMENT/PHYSICS
    { question: "The purpose of the collimator mirror in the x-ray tube housing is to:", optionA: "Filter the beam", optionB: "Deflect the light field to simulate the x-ray field for alignment", optionC: "Focus the electron beam", optionD: "Cool the anode", correctAnswer: "B", rationale: "The collimator mirror is a transparent mirror that redirects the light from the localizing lamp to project a light field onto the patient that simulates the x-ray field for centering and alignment.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 1, topic: "X-ray Equipment" },
    { question: "The primary purpose of the focusing cup in the cathode is to:", optionA: "Heat the filament", optionB: "Focus the electron stream toward the focal spot on the anode", optionC: "Filter x-rays", optionD: "Cool the cathode", correctAnswer: "B", rationale: "The focusing cup (negatively charged) surrounds the filament and electrostatically repels the thermionically emitted electrons, focusing them into a narrow stream directed at the focal spot on the anode.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "X-ray Tube" },
    { question: "In a three-phase 12-pulse generator, the voltage ripple is approximately:", optionA: "100%", optionB: "4%", optionC: "13%", optionD: "50%", correctAnswer: "B", rationale: "Three-phase 12-pulse generators have approximately 4% voltage ripple. For comparison: single-phase = 100%, 3-phase 6-pulse = 13%, high-frequency = <1%.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 3, topic: "X-ray Equipment" },
    { question: "Tube warm-up procedures are important because:", optionA: "They calibrate the kVp", optionB: "Gradual heating prevents thermal shock to the cold anode, which can crack the anode disc", optionC: "They reduce patient dose", optionD: "They improve image quality", correctAnswer: "B", rationale: "A cold anode can crack from thermal shock if subjected to high-load exposures immediately. Warm-up procedures gradually bring the anode to operating temperature, preventing damage and extending tube life.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "X-ray Tube" },
    { question: "The phototimer in AEC systems uses:", optionA: "A thermometer", optionB: "Ionization chambers or solid-state detectors positioned behind the cassette/IR to measure transmitted radiation", optionC: "A light meter", optionD: "A pressure sensor", correctAnswer: "B", rationale: "AEC phototimers use ionization chambers or solid-state detectors placed behind the IR. When the charge collected reaches a preset level (corresponding to proper exposure), the exposure is terminated.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "Exposure Factors" },

    // QC/QA
    { question: "Processor quality control in film-based radiography includes daily monitoring of:", optionA: "Only temperature", optionB: "Speed index, contrast index, and base-plus-fog using a sensitometer and densitometer", optionC: "Only developer strength", optionD: "Only fixer temperature", correctAnswer: "B", rationale: "Daily processor QC uses sensitometric strips to monitor speed (mid-density step), contrast (density difference), and base-plus-fog (unexposed area). Control charts track trends to detect processor drift.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "Quality Control" },
    { question: "A wire mesh test is used to evaluate:", optionA: "kVp accuracy", optionB: "Screen-film contact (in CR/film systems)", optionC: "Timer accuracy", optionD: "mA linearity", correctAnswer: "B", rationale: "The wire mesh test places a copper wire mesh on the cassette and exposes it. Areas of poor screen-film contact appear as darker or blurred regions compared to the sharp, uniform mesh pattern in well-contacted areas.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "Quality Control" },
    { question: "The half-value layer (HVL) test verifies:", optionA: "Image resolution", optionB: "Beam quality and adequacy of beam filtration", optionC: "Patient dose directly", optionD: "mA accuracy", correctAnswer: "B", rationale: "The HVL test measures beam quality (hardness) by determining the thickness of aluminum required to reduce beam intensity by 50%. It verifies that total beam filtration meets regulatory requirements.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "Quality Control" },
    { question: "Spatial resolution of a digital detector is tested using:", optionA: "A densitometer", optionB: "A resolution bar pattern (line pair test tool) or star pattern", optionC: "A sensitometer", optionD: "A thermometer", correctAnswer: "B", rationale: "Resolution test tools with known line-pair frequencies are imaged to determine the limiting spatial resolution (lp/mm) of the digital detector. The smallest resolvable line-pair group indicates the system's resolution limit.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "Quality Control" },
    { question: "mA reciprocity testing verifies that:", optionA: "kVp is accurate", optionB: "Different mA-time combinations producing the same mAs yield the same detector exposure", optionC: "The timer is accurate", optionD: "Filtration is adequate", correctAnswer: "B", rationale: "Reciprocity testing verifies that exposure output is consistent across different mA-time combinations that produce the same mAs. For example, 200 mA × 0.1s should produce the same output as 400 mA × 0.05s.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "Quality Control" },

    // CONTRAST/SPECIAL PROCEDURES
    { question: "The phase of CT enhancement where the liver shows maximum contrast between hepatic lesions and normal parenchyma is:", optionA: "Arterial phase", optionB: "Portal venous phase (60-70 seconds post-injection)", optionC: "Non-contrast phase", optionD: "Delayed phase", correctAnswer: "B", rationale: "The portal venous phase (60-70 seconds) provides maximum liver parenchymal enhancement because the liver receives 75-80% of its blood supply from the portal vein. Most liver lesions appear hypodense relative to enhanced parenchyma.", modality: "CT", bodyPart: "Abdomen", category: "Radiographic Procedures", difficulty: 3, topic: "CT Imaging" },
    { question: "The standard oral contrast preparation for CT abdomen requires:", optionA: "No preparation", optionB: "Drinking dilute oral contrast 1-2 hours before the scan to opacify the GI tract", optionC: "IV contrast only", optionD: "Rectal contrast only", correctAnswer: "B", rationale: "Oral contrast (dilute barium or iodinated solution) is ingested 1-2 hours before abdominal CT to opacify the GI tract, helping distinguish bowel loops from lymph nodes, masses, and other structures.", modality: "CT", bodyPart: "Abdomen", category: "Radiographic Procedures", difficulty: 2, topic: "CT Imaging" },
    { question: "Upper GI (UGI) series examines:", optionA: "The colon", optionB: "The esophagus, stomach, and duodenum using barium contrast under fluoroscopy", optionC: "The kidneys", optionD: "The gallbladder", correctAnswer: "B", rationale: "The upper GI series uses barium (single or double contrast) under fluoroscopy to evaluate the esophagus, stomach, and duodenum for ulcers, masses, hiatal hernia, reflux, and motility disorders.", modality: "X-ray", bodyPart: "GI Tract", category: "Radiographic Procedures", difficulty: 1, topic: "GI Radiography" },
    { question: "A double-contrast barium enema uses:", optionA: "Only barium", optionB: "Barium to coat the bowel wall and air insufflation to distend the colon", optionC: "Only air", optionD: "Only water-soluble contrast", correctAnswer: "B", rationale: "Double-contrast barium enema uses a thin layer of high-density barium to coat the mucosal surface, followed by air insufflation to distend the colon. This provides excellent mucosal detail for polyp and lesion detection.", modality: "X-ray", bodyPart: "Abdomen", category: "Radiographic Procedures", difficulty: 2, topic: "GI Radiography" },
    { question: "For a hysterosalpingogram (HSG), the contrast agent used is:", optionA: "Barium", optionB: "Water-soluble iodinated contrast injected through the cervix", optionC: "Gadolinium", optionD: "Air only", correctAnswer: "B", rationale: "HSG uses water-soluble iodinated contrast injected through the cervix to evaluate the uterine cavity and fallopian tube patency. It is commonly performed for infertility evaluation.", modality: "X-ray", bodyPart: "Pelvis", category: "Radiographic Procedures", difficulty: 2, topic: "GU Radiography" },
    { question: "Voiding cystourethrography (VCUG) is performed to evaluate:", optionA: "Kidney function", optionB: "Vesicoureteral reflux (VUR), bladder anatomy, and urethral patency", optionC: "Liver disease", optionD: "Gallstones", correctAnswer: "B", rationale: "VCUG fills the bladder with contrast via catheter and images during voiding to evaluate vesicoureteral reflux, bladder anatomy, diverticula, and urethral disorders. Common in pediatric patients.", modality: "X-ray", bodyPart: "Pelvis", category: "Radiographic Procedures", difficulty: 2, topic: "GU Radiography" },
    { question: "Myelography is used to evaluate:", optionA: "Blood vessels", optionB: "The spinal canal and nerve roots by injecting contrast into the subarachnoid space", optionC: "Joints", optionD: "Muscles", correctAnswer: "B", rationale: "Myelography involves injection of iodinated contrast into the subarachnoid space (typically via lumbar puncture) to outline the spinal cord, nerve roots, and subarachnoid space. Often combined with CT (CT myelography).", modality: "X-ray", bodyPart: "Spine", category: "Radiographic Procedures", difficulty: 2, topic: "Special Procedures" },
    { question: "Arthrography involves:", optionA: "Imaging blood vessels", optionB: "Injection of contrast (and/or air) into a joint space followed by imaging to evaluate internal joint structures", optionC: "Imaging bones only", optionD: "CT without contrast", correctAnswer: "B", rationale: "Arthrography involves injecting contrast media (single or double contrast) into a joint to evaluate internal structures such as ligaments, menisci, cartilage, and the joint capsule. Often combined with MRI (MR arthrography).", modality: "X-ray", bodyPart: "General", category: "Radiographic Procedures", difficulty: 2, topic: "Special Procedures" },

    // ADDITIONAL RADIATION PROTECTION
    { question: "Personal dosimeters measure:", optionA: "Patient dose", optionB: "The occupational radiation exposure received by the individual wearing the dosimeter", optionC: "Room radiation levels", optionD: "X-ray output", correctAnswer: "B", rationale: "Personal dosimeters (OSL, TLD, or electronic) measure the cumulative radiation exposure to the individual worker. They are worn at collar level outside lead apron and exchanged at regular intervals for reading.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 1, topic: "Personnel Monitoring" },
    { question: "The radiation weighting factor (wR) for x-rays and gamma rays is:", optionA: "5", optionB: "1", optionC: "10", optionD: "20", correctAnswer: "B", rationale: "X-rays and gamma rays have a radiation weighting factor of 1. Alpha particles have wR = 20, neutrons vary (5-20), and protons have wR = 2. The weighting factor reflects relative biological effectiveness.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 2, topic: "Dosimetry" },
    { question: "The annual occupational effective dose limit in Canada is:", optionA: "10 mSv", optionB: "50 mSv (with 100 mSv over 5 consecutive years)", optionC: "150 mSv", optionD: "500 mSv", correctAnswer: "B", rationale: "CNSC regulations set the annual occupational effective dose limit at 50 mSv, with a cumulative limit of 100 mSv over 5 consecutive years (averaging 20 mSv/year).", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 2, topic: "Dose Limits" },
    { question: "The cell type most sensitive to radiation is:", optionA: "Mature muscle cells", optionB: "Lymphocytes", optionC: "Nerve cells", optionD: "Mature red blood cells", correctAnswer: "B", rationale: "Lymphocytes are the most radiosensitive blood cells, showing measurable decrease at doses as low as 0.25 Gy. Other radiosensitive cells include spermatogonia, erythroblasts, and intestinal crypt cells.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 2, topic: "Radiation Biology" },
    { question: "The target theory of radiation biology states:", optionA: "All cells are equally sensitive", optionB: "DNA is the critical target for radiation damage — hits to DNA cause the most significant biological effects", optionC: "Only the cell membrane is affected", optionD: "Proteins are the main target", correctAnswer: "B", rationale: "The target theory identifies DNA as the critical target for radiation-induced biological damage. Direct hits to DNA can cause single-strand breaks, double-strand breaks, base damage, and cross-links.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 2, topic: "Radiation Biology" },
    { question: "The direct effect of radiation involves:", optionA: "Production of free radicals", optionB: "Direct interaction of radiation with a critical biological molecule (DNA), causing ionization", optionC: "Only thermal damage", optionD: "Chemical reaction with water", correctAnswer: "B", rationale: "Direct effect occurs when radiation directly ionizes DNA or other critical molecules. It accounts for about 1/3 of radiation damage in hydrated cells. The remaining 2/3 is from indirect effect (free radicals from water radiolysis).", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 2, topic: "Radiation Biology" },
    { question: "The indirect effect of radiation involves:", optionA: "Direct DNA ionization", optionB: "Radiation interacting with water molecules to produce free radicals (OH•) that damage DNA", optionC: "Thermal heating of tissue", optionD: "Electromagnetic interference", correctAnswer: "B", rationale: "Indirect effect involves radiation ionizing water molecules (radiolysis), producing highly reactive free radicals (OH•, H•) that damage nearby DNA. Since cells are ~80% water, indirect effect accounts for ~2/3 of biological damage.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 2, topic: "Radiation Biology" },
    { question: "Oxygen enhancement ratio (OER) indicates:", optionA: "The amount of oxygen in blood", optionB: "That oxygenated tissues are more radiosensitive than hypoxic tissues", optionC: "Oxygen consumption during exposure", optionD: "Breathing rate during imaging", correctAnswer: "B", rationale: "OER (typically ~2.5-3.0 for x-rays) indicates that well-oxygenated cells require lower doses to produce the same biological effect compared to hypoxic cells. Oxygen 'fixes' (makes permanent) the free radical damage.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 3, topic: "Radiation Biology" },
    { question: "The concept of dose limitation in radiation protection means:", optionA: "No one should ever be exposed", optionB: "Individual doses should not exceed specified limits to prevent deterministic effects and reduce stochastic risk to an acceptable level", optionC: "Only patients have dose limits", optionD: "There are no dose limits for workers", correctAnswer: "B", rationale: "Dose limitation (ICRP Principle 3) sets upper bounds on individual doses to prevent deterministic effects and keep stochastic risk at an acceptably low level. Limits differ for workers and the public.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 2, topic: "Dose Limits" },
    { question: "Structural shielding design for an x-ray room considers:", optionA: "Only the type of exam", optionB: "Workload (W), use factor (U), occupancy factor (T), and distance to occupied areas", optionC: "Only the kVp used", optionD: "Only the room size", correctAnswer: "B", rationale: "Shielding calculations use W (total weekly mA-min), U (fraction of time beam is directed at a barrier), T (fraction of time area is occupied), distance, and dose limits to determine required barrier thickness.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 3, topic: "Structural Shielding" },

    // ADDITIONAL IMAGE EVALUATION/QUALITY
    { question: "On a well-positioned lateral chest, the sternum should appear:", optionA: "Rotated to one side", optionB: "In profile, with the posterior ribs nearly superimposed", optionC: "PA-facing", optionD: "Not visible", correctAnswer: "B", rationale: "A true lateral chest shows the sternum in profile with the posterior ribs and posterior costophrenic angles nearly superimposed. The thoracic vertebral bodies should show increasing lucency superiorly to inferiorly.", modality: "X-ray", bodyPart: "Chest", category: "Image Evaluation", difficulty: 2, topic: "Image Critique" },
    { question: "Signal-to-noise ratio (SNR) is important in digital radiography because:", optionA: "Higher SNR means noisier images", optionB: "Higher SNR means the useful signal is greater relative to noise, producing a cleaner image", optionC: "SNR is not important in digital imaging", optionD: "Lower SNR produces better images", correctAnswer: "B", rationale: "SNR quantifies the ratio of useful signal to random noise. Higher SNR produces cleaner images with better visibility of subtle structures. SNR increases with the square root of photon count.", modality: "X-ray", bodyPart: "General", category: "Image Evaluation", difficulty: 2, topic: "Image Quality" },
    { question: "Contrast-to-noise ratio (CNR) describes:", optionA: "Only spatial resolution", optionB: "The ability to distinguish between two adjacent structures of slightly different attenuation in the presence of noise", optionC: "Only patient dose", optionD: "Grid efficiency", correctAnswer: "B", rationale: "CNR measures how well two adjacent structures can be distinguished from each other in the presence of noise. Higher CNR allows detection of subtle density differences (e.g., small tumors in soft tissue).", modality: "X-ray", bodyPart: "General", category: "Image Evaluation", difficulty: 3, topic: "Image Quality" },
    { question: "A properly exposed KUB (abdominal radiograph) should demonstrate:", optionA: "Only the spine", optionB: "Psoas muscle margins, kidney outlines (if visible), liver edge, and bowel gas pattern", optionC: "Only the pelvis", optionD: "Only the chest", correctAnswer: "B", rationale: "A properly exposed KUB should show soft tissue structures including psoas margins, kidney outlines (when visible), liver edge, and the distribution of bowel gas. Both the diaphragm and symphysis pubis should be included.", modality: "X-ray", bodyPart: "Abdomen", category: "Image Evaluation", difficulty: 2, topic: "Image Critique" },
    { question: "The shoulder on an AP external rotation shows:", optionA: "Lesser tuberosity in profile", optionB: "Greater tuberosity in profile laterally and the bicipital groove facing anteriorly", optionC: "The scapula in Y-view", optionD: "The AC joint", correctAnswer: "B", rationale: "External rotation of the humerus (palm up, supinated) places the greater tuberosity laterally in profile, demonstrating it well. The bicipital groove faces anteriorly between the tuberosities.", modality: "X-ray", bodyPart: "Shoulder", category: "Image Evaluation", difficulty: 2, topic: "Image Critique" },
    { question: "On a properly positioned AP elbow, the joint space should appear:", optionA: "Closed", optionB: "Open, with the radial head slightly overlapping the proximal ulna", optionC: "Fully overlapping", optionD: "Not visible", correctAnswer: "B", rationale: "A proper AP elbow (full extension, hand supinated) shows the elbow joint space open. There is slight overlap of the proximal radius and ulna. The medial and lateral epicondyles should be in profile.", modality: "X-ray", bodyPart: "Elbow", category: "Image Evaluation", difficulty: 1, topic: "Image Critique" },

    // DIGITAL IMAGING ADVANCED
    { question: "The pixel size in a digital detector determines:", optionA: "Only image storage size", optionB: "The maximum spatial resolution and Nyquist frequency of the imaging system", optionC: "Only patient dose", optionD: "Only image brightness", correctAnswer: "B", rationale: "Smaller pixels allow higher spatial resolution. The Nyquist frequency (maximum resolvable frequency) equals 1/(2 × pixel size). For example, a 100 μm pixel size gives a Nyquist frequency of 5 lp/mm.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 3, topic: "Digital Imaging" },
    { question: "Image compression in PACS can be:", optionA: "Only lossy", optionB: "Lossless (reversible, no data lost) or lossy (irreversible, some data permanently removed)", optionC: "Only lossless", optionD: "Not possible with medical images", correctAnswer: "B", rationale: "Lossless compression reduces file size by ~2-3:1 without losing data. Lossy compression achieves higher ratios (10:1 or more) but permanently removes some data. Diagnostic images typically require lossless compression.", modality: "General", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "Digital Imaging" },
    { question: "The bit depth of a digital image determines:", optionA: "Spatial resolution", optionB: "The number of possible gray-scale levels (2^n) available for each pixel", optionC: "Image size on screen", optionD: "Patient dose", correctAnswer: "B", rationale: "Bit depth determines gray-scale range: 8-bit = 256 levels, 10-bit = 1024 levels, 12-bit = 4096 levels, 14-bit = 16384 levels. Higher bit depth provides better contrast resolution and more manipulation latitude.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "Digital Imaging" },
    { question: "RIS (Radiology Information System) is used for:", optionA: "Image storage", optionB: "Managing radiology department workflow including scheduling, reporting, billing, and patient tracking", optionC: "Image processing", optionD: "Radiation dose measurement", correctAnswer: "B", rationale: "RIS manages the administrative functions of a radiology department: scheduling, registration, tracking exams, report generation, billing, and management statistics. It interfaces with HIS and PACS via HL7.", modality: "General", bodyPart: "General", category: "Image Production", difficulty: 1, topic: "Digital Imaging" },
    { question: "HL7 (Health Level 7) is:", optionA: "A type of x-ray tube", optionB: "A standard for exchanging electronic health information between healthcare information systems", optionC: "An imaging protocol", optionD: "A radiation measurement unit", correctAnswer: "B", rationale: "HL7 is the standard for electronic health information exchange between different systems (HIS, RIS, EMR). While DICOM handles medical image data, HL7 handles patient demographics, orders, results, and reports.", modality: "General", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "Digital Imaging" },

    // PEDIATRIC AND GERIATRIC
    { question: "When imaging pediatric patients, the most important consideration is:", optionA: "Using adult technique", optionB: "Minimizing radiation dose while maintaining diagnostic image quality, using proper immobilization", optionC: "Always using a grid", optionD: "Using maximum kVp", correctAnswer: "B", rationale: "Pediatric patients are more radiosensitive than adults due to rapidly dividing cells and longer lifespan for effects to manifest. ALARA is critical: use appropriate technique reduction, proper collimation, and effective immobilization.", modality: "X-ray", bodyPart: "General", category: "Patient Care", difficulty: 1, topic: "Pediatric Radiography" },
    { question: "Immobilization devices for pediatric radiography include:", optionA: "Only sandbags", optionB: "Pigg-O-Stat, Papoose board, sandbags, tape, and parental assistance with lead protection", optionC: "Sedation only", optionD: "Straps only", correctAnswer: "B", rationale: "The Pigg-O-Stat immobilizes for upright chest views. The Papoose board secures for table procedures. Sandbags, tape, and stockinette may be used for extremities. Parent holding is used when other methods are inadequate (parent must wear lead).", modality: "X-ray", bodyPart: "General", category: "Patient Care", difficulty: 2, topic: "Pediatric Radiography" },
    { question: "When imaging a geriatric patient with osteoporosis, the technologist should:", optionA: "Use standard adult technique without modification", optionB: "Handle the patient gently, use reduced technique (lower mAs) due to decreased bone density, and assist with positioning", optionC: "Use maximum kVp", optionD: "Skip positioning aids", correctAnswer: "B", rationale: "Osteoporotic patients have decreased bone density requiring lower technique (especially mAs). Handle gently to prevent pathologic fractures. Use positioning aids for comfort and stability.", modality: "X-ray", bodyPart: "General", category: "Patient Care", difficulty: 2, topic: "Geriatric Considerations" },
    { question: "Effective communication with a hearing-impaired patient includes:", optionA: "Speaking louder only", optionB: "Facing the patient, speaking clearly, using written instructions, and ensuring visual cues for breathing instructions", optionC: "Using only hand signals", optionD: "Proceeding without instructions", correctAnswer: "B", rationale: "Effective communication includes facing the patient (for lip reading), speaking clearly and slowly, using written instructions, visual breathing cues (hand signals), and allowing extra time for understanding.", modality: "General", bodyPart: "General", category: "Patient Care", difficulty: 1, topic: "Patient Communication" },
    { question: "When imaging a patient with dementia or confusion, the technologist should:", optionA: "Rush through the exam", optionB: "Speak calmly, give simple one-step instructions, maintain eye contact, and have assistance available", optionC: "Skip the exam", optionD: "Use restraints immediately", correctAnswer: "B", rationale: "Confused or dementia patients require calm, patient communication with simple, repeated instructions. Maintain eye contact, use a reassuring tone, have assistance ready, and allow extra time.", modality: "General", bodyPart: "General", category: "Patient Care", difficulty: 1, topic: "Patient Communication" },

    // CANADIAN REGULATORY
    { question: "In Canada, who is responsible for licensing x-ray equipment and setting provincial radiation safety standards?", optionA: "The federal government only", optionB: "Provincial/territorial governments through their respective radiation safety agencies", optionC: "The hospital only", optionD: "The manufacturer", correctAnswer: "B", rationale: "In Canada, radiation protection for medical x-ray equipment is regulated provincially/territorially. Each province has its own radiation safety legislation and licensing requirements. The CNSC handles nuclear substances.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 2, topic: "Regulations" },
    { question: "CAMRT stands for:", optionA: "Canadian Association of Magnetic Resonance Technologists", optionB: "Canadian Association of Medical Radiation Technologists", optionC: "Canadian Association of Medical Radiologists", optionD: "Canadian Academy of Medical Radiation Therapy", correctAnswer: "B", rationale: "CAMRT is the Canadian Association of Medical Radiation Technologists, the national professional association and certifying body for medical radiation technologists in Canada.", modality: "General", bodyPart: "General", category: "Patient Care", difficulty: 1, topic: "Professional Practice" },
    { question: "The CAMRT certification examination tests competency in:", optionA: "Only positioning", optionB: "Patient care, radiation protection, image production, image evaluation, and radiographic procedures", optionC: "Only radiation physics", optionD: "Only anatomy", correctAnswer: "B", rationale: "The CAMRT certification exam covers five main domains: Patient Care & Safety, Radiation Protection, Image Production, Image Evaluation, and Radiographic Procedures, reflecting the full scope of practice.", modality: "General", bodyPart: "General", category: "Patient Care", difficulty: 1, topic: "Professional Practice" },
    { question: "Continuing professional development (CPD) for CAMRT members requires:", optionA: "No ongoing education", optionB: "Regular completion of professional development activities to maintain certification and demonstrate competency", optionC: "Retaking the exam every year", optionD: "Only attending conferences", correctAnswer: "B", rationale: "CAMRT requires members to participate in continuing professional development to maintain certification, ensure currency of knowledge and skills, and demonstrate ongoing competency.", modality: "General", bodyPart: "General", category: "Patient Care", difficulty: 1, topic: "Professional Practice" },

    // ANATOMY
    { question: "The carpal bones of the wrist, from lateral to medial in the proximal row, are:", optionA: "Trapezium, trapezoid, capitate, hamate", optionB: "Scaphoid, lunate, triquetrum, pisiform", optionC: "Navicular, cuboid, lateral cuneiform, medial cuneiform", optionD: "First through fourth metacarpals", correctAnswer: "B", rationale: "The proximal carpal row (lateral to medial): scaphoid, lunate, triquetrum, pisiform. The distal row: trapezium, trapezoid, capitate, hamate. Mnemonic: Some Lovers Try Positions That They Can't Handle.", modality: "X-ray", bodyPart: "Wrist", category: "Radiographic Procedures", difficulty: 1, topic: "Anatomy" },
    { question: "The tarsal bones include all EXCEPT:", optionA: "Calcaneus", optionB: "Trapezoid", optionC: "Talus", optionD: "Navicular", correctAnswer: "B", rationale: "The trapezoid is a carpal bone (wrist), not a tarsal bone. The 7 tarsals are: calcaneus, talus, navicular, cuboid, and three cuneiforms (medial, intermediate, lateral).", modality: "X-ray", bodyPart: "Foot", category: "Radiographic Procedures", difficulty: 1, topic: "Anatomy" },
    { question: "The carina of the trachea is located at approximately which vertebral level?", optionA: "C7", optionB: "T5-T6", optionC: "T10", optionD: "L1", correctAnswer: "B", rationale: "The carina (bifurcation of the trachea into the right and left main bronchi) is located at approximately T5-T6 level. This is an important landmark on chest radiographs.", modality: "X-ray", bodyPart: "Chest", category: "Image Evaluation", difficulty: 2, topic: "Anatomy" },
    { question: "The intervertebral foramina of the lumbar spine are best demonstrated on:", optionA: "AP projection", optionB: "Lateral projection", optionC: "Oblique projection", optionD: "PA projection", correctAnswer: "B", rationale: "Lumbar intervertebral foramina are directed laterally and are best demonstrated on the lateral projection. This differs from the cervical spine, where the foramina are best shown on oblique views (45-degree oblique).", modality: "X-ray", bodyPart: "Lumbar Spine", category: "Radiographic Procedures", difficulty: 2, topic: "Anatomy" },
    { question: "The zygapophyseal (facet) joints of the lumbar spine are demonstrated on:", optionA: "AP projection", optionB: "45-degree oblique projection", optionC: "Lateral projection", optionD: "Axial CT only", correctAnswer: "B", rationale: "Lumbar facet (zygapophyseal) joints are oriented at approximately 45 degrees to the sagittal plane and are best demonstrated on the 45-degree oblique projection (showing the 'Scotty dog').", modality: "X-ray", bodyPart: "Lumbar Spine", category: "Radiographic Procedures", difficulty: 2, topic: "Anatomy" },
    { question: "The olecranon process is part of:", optionA: "The radius", optionB: "The ulna", optionC: "The humerus", optionD: "The scapula", correctAnswer: "B", rationale: "The olecranon process is the large proximal projection of the ulna that forms the posterior point of the elbow. It articulates with the olecranon fossa of the humerus during extension.", modality: "X-ray", bodyPart: "Elbow", category: "Radiographic Procedures", difficulty: 1, topic: "Anatomy" },
    { question: "The acromion process is part of:", optionA: "The clavicle", optionB: "The scapula", optionC: "The humerus", optionD: "The sternum", correctAnswer: "B", rationale: "The acromion is the lateral extension of the spine of the scapula that forms the roof of the shoulder and articulates with the distal clavicle at the acromioclavicular (AC) joint.", modality: "X-ray", bodyPart: "Shoulder", category: "Radiographic Procedures", difficulty: 1, topic: "Anatomy" },
    { question: "The sacroiliac (SI) joints are best demonstrated on:", optionA: "AP pelvis", optionB: "AP oblique with 25-30 degrees of posterior oblique rotation to the affected side", optionC: "Lateral pelvis", optionD: "AP hip", correctAnswer: "B", rationale: "The SI joints are oriented obliquely and are best demonstrated with 25-30 degrees of posterior oblique rotation (RPO for right SI joint, LPO for left). The joint closest to the IR is demonstrated.", modality: "X-ray", bodyPart: "Pelvis", category: "Radiographic Procedures", difficulty: 2, topic: "Lower Extremity" },
    { question: "The pedicles of the vertebral column connect:", optionA: "Spinous process to transverse process", optionB: "Vertebral body to the vertebral arch (posterior elements)", optionC: "Adjacent vertebrae", optionD: "Ribs to vertebrae", correctAnswer: "B", rationale: "Pedicles are short, thick processes that connect the vertebral body anteriorly to the vertebral arch posteriorly. They form the lateral walls of the vertebral foramen and are important landmarks for evaluating rotation on AP views.", modality: "X-ray", bodyPart: "Spine", category: "Radiographic Procedures", difficulty: 1, topic: "Anatomy" },
    { question: "The medial malleolus is part of:", optionA: "The fibula", optionB: "The tibia", optionC: "The talus", optionD: "The calcaneus", correctAnswer: "B", rationale: "The medial malleolus is the distal medial projection of the tibia forming the medial wall of the ankle mortise. The lateral malleolus is the distal end of the fibula.", modality: "X-ray", bodyPart: "Ankle", category: "Radiographic Procedures", difficulty: 1, topic: "Anatomy" },
    { question: "The coronoid process is found on:", optionA: "The radius", optionB: "The ulna (and the mandible)", optionC: "The humerus", optionD: "The femur", correctAnswer: "B", rationale: "The coronoid process of the ulna is a beak-like projection on the anterior proximal ulna that articulates with the coronoid fossa of the humerus during flexion. A separate coronoid process exists on the mandible.", modality: "X-ray", bodyPart: "Elbow", category: "Radiographic Procedures", difficulty: 1, topic: "Anatomy" },
    { question: "The manubrium, body, and xiphoid process are parts of:", optionA: "The clavicle", optionB: "The sternum", optionC: "The scapula", optionD: "The ribs", correctAnswer: "B", rationale: "The sternum consists of three parts: manubrium (superior, articulates with clavicles and first two ribs), body (largest portion, articulates with ribs 2-7), and xiphoid process (inferior cartilaginous tip).", modality: "X-ray", bodyPart: "Sternum", category: "Radiographic Procedures", difficulty: 1, topic: "Anatomy" },
  ];

  qs.push(...bodyPartQuestions);
  return qs;
}

export function generateBulkQuestions2(): CamrtQuestion[] {
  const qs: CamrtQuestion[] = [];

  const moreQuestions: CamrtQuestion[] = [
    // MORE PATIENT CARE (BATCH 2)
    { question: "A patient scheduled for a barium swallow should be NPO (nothing by mouth) for:", optionA: "1 hour", optionB: "At least 8 hours (overnight) prior to the examination", optionC: "24 hours", optionD: "No fasting is required", correctAnswer: "B", rationale: "NPO for at least 8 hours ensures an empty stomach for optimal mucosal coating with barium. Food residue can mimic pathology or obscure lesions.", modality: "X-ray", bodyPart: "GI Tract", category: "Patient Care", difficulty: 2, topic: "Patient Preparation" },
    { question: "The medical term for abnormally low blood pressure is:", optionA: "Hypertension", optionB: "Hypotension", optionC: "Tachycardia", optionD: "Bradycardia", correctAnswer: "B", rationale: "Hypotension is systolic BP below 90 mmHg or diastolic below 60 mmHg. It can cause dizziness, fainting, and shock. It may occur during contrast reactions or vasovagal episodes.", modality: "General", bodyPart: "General", category: "Patient Care", difficulty: 1, topic: "Vital Signs" },
    { question: "Contact precautions are required for patients with:", optionA: "Tuberculosis", optionB: "MRSA, VRE, C. difficile, and other contact-transmitted organisms", optionC: "Measles", optionD: "Chickenpox", correctAnswer: "B", rationale: "Contact precautions (gown + gloves, dedicated equipment) are used for organisms spread by direct or indirect contact: MRSA, VRE, C. difficile, scabies, and some wound infections.", modality: "General", bodyPart: "General", category: "Patient Care", difficulty: 2, topic: "Infection Control" },
    { question: "Airborne precautions are required for patients with:", optionA: "MRSA", optionB: "Tuberculosis, measles, varicella (chickenpox), and disseminated herpes zoster", optionC: "C. difficile", optionD: "Wound infections", correctAnswer: "B", rationale: "Airborne precautions (N95 respirator, negative pressure room, closed door) are required for organisms that remain suspended in air: TB, measles, varicella, smallpox, and disseminated zoster.", modality: "General", bodyPart: "General", category: "Patient Care", difficulty: 2, topic: "Infection Control" },
    { question: "Droplet precautions are required for patients with:", optionA: "TB", optionB: "Influenza, pertussis, meningococcal disease, mumps, and rubella", optionC: "MRSA", optionD: "HIV", correctAnswer: "B", rationale: "Droplet precautions (surgical mask within 3 feet, eye protection) are used for organisms spread by large droplets generated during coughing, sneezing, or talking: influenza, pertussis, mumps, rubella.", modality: "General", bodyPart: "General", category: "Patient Care", difficulty: 2, topic: "Infection Control" },
    { question: "The Trendelenburg position involves:", optionA: "Head elevated, feet down", optionB: "Head lower than feet (body tilted 15-30 degrees with head down)", optionC: "Flat supine", optionD: "Prone", correctAnswer: "B", rationale: "Trendelenburg position places the patient supine with head lower than feet (15-30 degrees). Used to promote venous return in hypovolemic shock or to fill dependent regions during fluoroscopy.", modality: "General", bodyPart: "General", category: "Patient Care", difficulty: 1, topic: "Patient Positioning" },
    { question: "The Fowler's position involves:", optionA: "Head down, feet elevated", optionB: "Patient sitting upright or semi-upright (45-90 degrees)", optionC: "Flat supine", optionD: "Lateral decubitus", correctAnswer: "B", rationale: "Fowler's position: semi-Fowler's = 30-45 degrees, Fowler's = 45-60 degrees, high Fowler's = 60-90 degrees. Used for respiratory distress, post-surgical patients, and upright chest/abdominal imaging.", modality: "General", bodyPart: "General", category: "Patient Care", difficulty: 1, topic: "Patient Positioning" },
    { question: "Before performing venipuncture, the technologist should:", optionA: "Begin immediately", optionB: "Verify patient identity, check for allergies, assess veins, apply tourniquet, and clean the site with antiseptic", optionC: "Only check the patient's name", optionD: "Skip the tourniquet", correctAnswer: "B", rationale: "Proper venipuncture preparation includes: verify identity, check allergies and medical history, assess vein suitability, apply tourniquet 3-4 inches above the site, clean with antiseptic, and wait for it to dry.", modality: "CT", bodyPart: "General", category: "Patient Care", difficulty: 2, topic: "Venipuncture & Contrast Media" },
    { question: "A butterfly (winged infusion) needle is used when:", optionA: "High flow rates are needed", optionB: "Small, fragile, or difficult veins (pediatric, elderly, or hand veins) require access", optionC: "Large volumes are needed", optionD: "The patient refuses IV access", correctAnswer: "B", rationale: "Butterfly needles are used for difficult venous access: small veins, fragile veins (elderly), pediatric patients, or hand veins. They provide better control but have limited flow rates compared to angiocatheters.", modality: "CT", bodyPart: "General", category: "Patient Care", difficulty: 2, topic: "Venipuncture & Contrast Media" },
    { question: "Medical asepsis (clean technique) differs from surgical asepsis (sterile technique) in that:", optionA: "They are identical", optionB: "Medical asepsis reduces the number of microorganisms; surgical asepsis eliminates all microorganisms from an area", optionC: "Surgical asepsis is less strict", optionD: "Medical asepsis requires sterilization", correctAnswer: "B", rationale: "Medical asepsis (clean technique): reduces microorganism number through hand hygiene, disinfection, and barriers. Surgical asepsis (sterile technique): complete elimination of all microorganisms through sterilization and sterile field maintenance.", modality: "General", bodyPart: "General", category: "Patient Care", difficulty: 2, topic: "Infection Control" },

    // MORE RADIATION PROTECTION (BATCH 2)
    { question: "The purpose of the primary barrier in an x-ray room is to:", optionA: "Support the wall", optionB: "Attenuate the primary (useful) x-ray beam directed toward it during exposures", optionC: "Block sound", optionD: "Prevent fire", correctAnswer: "B", rationale: "The primary barrier is the wall (or floor/ceiling) that the primary beam can be directed toward. It must be thicker than secondary barriers because it attenuates the full intensity of the primary beam.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 2, topic: "Structural Shielding" },
    { question: "Secondary barriers protect against:", optionA: "Primary beam", optionB: "Scatter radiation and leakage radiation from the tube housing", optionC: "Electromagnetic interference", optionD: "Sound", correctAnswer: "B", rationale: "Secondary barriers attenuate scatter radiation (from patient) and leakage radiation (from tube housing). They are thinner than primary barriers because scatter and leakage are lower intensity than the primary beam.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 2, topic: "Structural Shielding" },
    { question: "Radiation survey instruments (survey meters) are used to:", optionA: "Measure patient dose", optionB: "Measure ambient radiation levels in areas around x-ray rooms to verify shielding adequacy", optionC: "Calibrate x-ray tubes", optionD: "Measure image quality", correctAnswer: "B", rationale: "Survey meters (ionization chambers, Geiger-Müller counters) measure ambient radiation levels to verify that shielding meets regulatory limits for controlled and uncontrolled areas.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 2, topic: "Radiation Measurement" },
    { question: "Genetic (hereditary) effects of radiation:", optionA: "Are deterministic", optionB: "Are stochastic effects that may appear in future generations of the irradiated individual", optionC: "Only affect the irradiated person", optionD: "Have a clear threshold", correctAnswer: "B", rationale: "Genetic effects are stochastic — mutations in germ cells (sperm/ova) can be transmitted to offspring. They have no threshold dose (LNT model). While demonstrated in animals, hereditary effects have not been conclusively demonstrated in humans.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 2, topic: "Radiation Biology" },
    { question: "The cell survival curve shows:", optionA: "Patient dose limits", optionB: "The relationship between radiation dose and the fraction of cells surviving, with a shoulder and exponential decline", optionC: "X-ray output", optionD: "kVp vs. mAs relationship", correctAnswer: "B", rationale: "Cell survival curves plot surviving cell fraction vs. dose. The shoulder region represents sublethal damage repair, followed by exponential cell killing. High-LET radiation has no shoulder (single-hit killing).", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 3, topic: "Radiation Biology" },
    { question: "The relative risk model for radiation-induced cancer assumes:", optionA: "Risk decreases with time", optionB: "Excess cancer risk is proportional to the natural cancer rate, increasing with age", optionC: "Risk is constant at all ages", optionD: "Risk is zero after 10 years", correctAnswer: "B", rationale: "The relative risk (multiplicative) model assumes excess cancer risk is proportional to the background cancer rate. Since cancer rates increase with age, the excess risk from radiation also increases with age.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 3, topic: "Radiation Biology" },
    { question: "The annual skin dose limit for occupational workers is:", optionA: "50 mSv", optionB: "500 mSv", optionC: "150 mSv", optionD: "1 mSv", correctAnswer: "B", rationale: "The CNSC annual skin dose limit (equivalent dose to skin) is 500 mSv per year. This is higher than the effective dose limit (50 mSv) because skin is less radiosensitive than internal organs.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 2, topic: "Dose Limits" },
    { question: "OSL (optically stimulated luminescence) dosimeters work by:", optionA: "Measuring temperature", optionB: "Stimulating stored energy release with laser light; the luminescence is proportional to radiation dose received", optionC: "Using photographic film", optionD: "Counting particles", correctAnswer: "B", rationale: "OSL dosimeters use aluminum oxide (Al2O3:C) crystals that store energy when irradiated. Green laser light stimulates luminescence proportional to the radiation dose received. They can be re-read multiple times.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 2, topic: "Personnel Monitoring" },
    { question: "Film badge dosimeters have been largely replaced by OSL and TLD because:", optionA: "Film badges are more accurate", optionB: "OSL/TLD can be re-read, have longer shelf life, are not affected by heat/humidity, and provide more accurate readings", optionC: "Film badges are cheaper", optionD: "Film badges are reusable", correctAnswer: "B", rationale: "Film badges are affected by heat, humidity, and pressure; cannot be re-read; and have a limited dose range. OSL dosimeters are re-readable, have wide dose range, long shelf life, and are unaffected by environmental conditions.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 2, topic: "Personnel Monitoring" },
    { question: "For a patient who may be pregnant and requires an urgent abdomen/pelvis radiograph:", optionA: "Refuse the exam entirely", optionB: "Consult with the radiologist, use the lowest possible technique, tight collimation, and ensure the benefit outweighs the risk", optionC: "Proceed without any modifications", optionD: "Wait until after delivery", correctAnswer: "B", rationale: "If the exam is clinically justified and urgent, it should proceed with dose optimization: lowest acceptable technique, tight collimation, proper positioning, and no repeat exposures. Document the clinical justification.", modality: "X-ray", bodyPart: "General", category: "Radiation Protection", difficulty: 2, topic: "Pregnancy" },

    // MORE IMAGE PRODUCTION (BATCH 2)
    { question: "Quantum mottle (noise) in digital radiography is primarily controlled by:", optionA: "kVp", optionB: "mAs (the number of photons reaching the detector)", optionC: "SID", optionD: "Grid ratio", correctAnswer: "B", rationale: "Quantum noise is inversely related to the square root of photon count. Increasing mAs increases photons reaching the detector, reducing quantum noise. However, this increases patient dose and must follow ALARA.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "Image Quality" },
    { question: "The dynamic range of a digital detector refers to:", optionA: "Its physical size", optionB: "The range of x-ray exposures it can record as useful image data", optionC: "Its weight", optionD: "Its speed of readout", correctAnswer: "B", rationale: "Dynamic range is the ratio of maximum to minimum detectable signal. Digital detectors have much wider dynamic range than film (10,000:1 vs 100:1), meaning they can produce acceptable images over a wider range of exposures.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "Digital Imaging" },
    { question: "The purpose of image post-processing in digital radiography is to:", optionA: "Increase patient dose", optionB: "Optimize image appearance for diagnostic interpretation by adjusting contrast, brightness, edge enhancement, and noise reduction", optionC: "Change the patient's anatomy", optionD: "Reduce image resolution", correctAnswer: "B", rationale: "Post-processing adjusts the raw digital data for optimal diagnostic display. Techniques include windowing (level/width), edge enhancement, noise reduction, subtraction, and harmonization.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 1, topic: "Digital Imaging" },
    { question: "Off-focus radiation (extrafocal radiation) is produced when:", optionA: "The filament breaks", optionB: "Electrons in the beam interact with parts of the anode outside the focal spot", optionC: "The kVp is too low", optionD: "The grid is misaligned", correctAnswer: "B", rationale: "Off-focus (extrafocal) radiation is produced when electrons interact with anode surfaces outside the focal track (bombarding the face of the anode). It produces unwanted radiation outside the collimated field.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 3, topic: "X-ray Tube" },
    { question: "The anode heat storage capacity is measured in:", optionA: "Sievert", optionB: "Heat Units (HU) or Joules", optionC: "mAs", optionD: "kVp", correctAnswer: "B", rationale: "Heat storage capacity is measured in Heat Units (HU) or Joules. HU = kVp × mA × time × generator factor (1.0 for single-phase, 1.35 for 3-phase, 1.41 for high-frequency). Modern tubes have >1 million HU capacity.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "X-ray Tube" },
    { question: "The effect of added filtration on the x-ray beam is to:", optionA: "Increase the number of low-energy photons", optionB: "Remove low-energy photons, increasing average beam energy (hardening the beam) and reducing patient skin dose", optionC: "Decrease beam energy", optionD: "Have no effect", correctAnswer: "B", rationale: "Added filtration selectively removes low-energy photons that contribute to patient skin dose without reaching the detector. This hardens the beam (increases average energy) and shifts the spectrum toward higher energies.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "X-ray Physics" },
    { question: "The grid frequency (lines/cm or lines/inch) affects:", optionA: "Patient dose only", optionB: "Grid line visibility on the image — higher frequency grids are less likely to produce visible grid lines", optionC: "Only contrast", optionD: "Only resolution", correctAnswer: "B", rationale: "Grid frequency refers to the number of lead strips per unit length. Higher frequency grids (>60 lines/cm) produce less visible grid lines on the image. Low-frequency grids may show visible lines if stationary.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "Grids" },
    { question: "The primary controlling factor for radiographic contrast in film-screen systems is:", optionA: "mAs", optionB: "kVp", optionC: "SID", optionD: "Focal spot size", correctAnswer: "B", rationale: "kVp is the primary control for radiographic contrast. Lower kVp increases the photoelectric effect relative to Compton scatter, producing higher (shorter-scale) contrast. Higher kVp produces lower (longer-scale) contrast.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 1, topic: "Exposure Factors" },
    { question: "The primary controlling factor for image receptor exposure (density) is:", optionA: "kVp", optionB: "mAs", optionC: "SID", optionD: "Grid ratio", correctAnswer: "B", rationale: "mAs (milliampere-seconds) directly controls the quantity of x-ray photons produced and thus the exposure reaching the detector. Doubling mAs doubles the receptor exposure.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 1, topic: "Exposure Factors" },
    { question: "Indirect conversion DR detectors use:", optionA: "Amorphous selenium", optionB: "A scintillator (CsI or Gd2O2S) to convert x-rays to light, then a photodiode array to convert light to electrical signal", optionC: "Film", optionD: "PSP plates", correctAnswer: "B", rationale: "Indirect DR uses a two-step process: 1) scintillator converts x-rays to visible light, 2) photodiode/TFT array converts light to electrical charge. CsI needles (structured) provide better resolution than amorphous Gd2O2S.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "Digital Imaging" },

    // MORE IMAGE EVALUATION (BATCH 2)
    { question: "On a properly positioned Waters view, the petrous ridges should project:", optionA: "Through the orbits", optionB: "Below the maxillary sinuses (below the sinus floor)", optionC: "Through the frontal sinuses", optionD: "Above the orbits", correctAnswer: "B", rationale: "The Waters view projects the petrous ridges below the maxillary sinus floors (at or below the inferior margins). This clears the maxillary sinuses for evaluation. If petrous ridges overlap the sinuses, the chin needs more extension.", modality: "X-ray", bodyPart: "Sinuses", category: "Image Evaluation", difficulty: 2, topic: "Image Critique" },
    { question: "On a lateral knee, the femoral condyles should appear:", optionA: "Widely separated", optionB: "Superimposed (with the patellofemoral joint space visible)", optionC: "Rotated", optionD: "Not visible", correctAnswer: "B", rationale: "A true lateral knee shows the femoral condyles nearly superimposed (posterior condyles aligned). The patellofemoral joint space should be visible. Condyle separation indicates rotation.", modality: "X-ray", bodyPart: "Knee", category: "Image Evaluation", difficulty: 2, topic: "Image Critique" },
    { question: "A portable chest radiograph appears lighter (underexposed) compared to department images. The primary cause is likely:", optionA: "Using a grid", optionB: "Reduced SID (typically 40 inches instead of 72 inches for portable) without adequate technique compensation", optionC: "Patient motion", optionD: "Wrong patient", correctAnswer: "B", rationale: "Portable chest radiographs use shorter SID (40 inches) which, per the inverse square law, increases intensity but also increases magnification. If technique is not adjusted or if scatter reduction is insufficient, image quality may differ.", modality: "X-ray", bodyPart: "Chest", category: "Image Evaluation", difficulty: 2, topic: "Image Critique" },
    { question: "Histogram analysis failure in digital radiography can be caused by:", optionA: "Proper positioning", optionB: "Collimation being too loose (exposing areas outside the patient), or extraneous objects in the field", optionC: "Correct technique", optionD: "Using the right detector", correctAnswer: "B", rationale: "Histogram analysis can fail when the processing algorithm cannot properly identify the relevant anatomy due to excessive exposed area outside the patient, extraneous objects (lead apron, IV pole), or inappropriate collimation.", modality: "X-ray", bodyPart: "General", category: "Image Evaluation", difficulty: 2, topic: "Artifacts" },
    { question: "Dead or defective detector elements (dels) in a flat-panel detector appear as:", optionA: "Grid lines", optionB: "Consistent white or black spots in the same location on every image", optionC: "Motion blur", optionD: "Random noise", correctAnswer: "B", rationale: "Defective detector elements produce consistent artifacts (white or black pixels) in the same location on every image. These are identified during detector calibration and corrected by interpolation from surrounding pixels.", modality: "X-ray", bodyPart: "General", category: "Image Evaluation", difficulty: 2, topic: "Artifacts" },
    { question: "Backscatter radiation can produce artifacts by:", optionA: "Improving image quality", optionB: "Causing extraneous image density from radiation reflected back from structures behind the image receptor", optionC: "Reducing patient dose", optionD: "Improving contrast", correctAnswer: "B", rationale: "Backscatter occurs when x-rays pass through the IR and scatter backward from the table or wall. Lead backing on cassettes/detectors reduces this. It appears as uniform fog degrading image quality.", modality: "X-ray", bodyPart: "General", category: "Image Evaluation", difficulty: 2, topic: "Artifacts" },
    { question: "CR plate reader artifacts (scan line artifacts) appear as:", optionA: "Random spots", optionB: "Regularly spaced lines in the scan direction caused by dust, dirt, or malfunctioning laser/light guide", optionC: "Grid lines", optionD: "Motion blur", correctAnswer: "B", rationale: "CR plate reader artifacts produce scan lines from dust on the light guide, dirty rollers, or laser fluctuations. They appear as regularly spaced lines parallel to the scan direction. Regular reader cleaning prevents them.", modality: "X-ray", bodyPart: "General", category: "Image Evaluation", difficulty: 2, topic: "Artifacts" },
    { question: "The cross-hatch (grid) pattern visible on an image indicates:", optionA: "Proper grid use", optionB: "A stationary grid was used, or the Bucky mechanism failed to move the grid during exposure", optionC: "Patient motion", optionD: "Overexposure", correctAnswer: "B", rationale: "Visible grid lines occur when a stationary grid is used (acceptable for portable exams at higher frequencies) or when the reciprocating Bucky mechanism fails to oscillate during the exposure.", modality: "X-ray", bodyPart: "General", category: "Image Evaluation", difficulty: 2, topic: "Artifacts" },
    { question: "On an AP lumbar spine, rotation is identified by:", optionA: "Symmetric pedicles", optionB: "Asymmetric distance between spinous processes and pedicles", optionC: "Good contrast", optionD: "Proper density", correctAnswer: "B", rationale: "On a properly positioned AP lumbar spine without rotation, spinous processes should be equidistant from both pedicles at each level. Asymmetric pedicle-to-spinous process distances indicate rotation.", modality: "X-ray", bodyPart: "Lumbar Spine", category: "Image Evaluation", difficulty: 2, topic: "Image Critique" },
    { question: "On a well-positioned lateral lumbar spine, the intervertebral disc spaces should appear:", optionA: "Closed", optionB: "Open, with posterior vertebral body margins superimposed", optionC: "Overlapping", optionD: "Not visible", correctAnswer: "B", rationale: "A true lateral lumbar spine shows open disc spaces, superimposed posterior vertebral body margins (indicating no rotation), and the spinous processes should project to one side.", modality: "X-ray", bodyPart: "Lumbar Spine", category: "Image Evaluation", difficulty: 2, topic: "Image Critique" },

    // MORE RADIOGRAPHIC PROCEDURES (BATCH 2)
    { question: "The Clements-Nakayama method is used for:", optionA: "Lateral skull", optionB: "AP projection of the hip on a trauma patient who cannot be rotated (horizontal beam through the hip from anterior)", optionC: "Lateral chest", optionD: "Oblique cervical spine", correctAnswer: "B", rationale: "The Clements-Nakayama method provides a modified lateral hip projection for trauma patients who cannot be moved. The beam enters from the anterior surface with the patient supine, providing an alternative to the cross-table lateral.", modality: "X-ray", bodyPart: "Hip", category: "Radiographic Procedures", difficulty: 3, topic: "Lower Extremity" },
    { question: "The AP axial projection of the clavicle uses:", optionA: "No tube angle", optionB: "15-30 degrees cephalad to project the clavicle above the ribs", optionC: "15 degrees caudad", optionD: "45 degrees cephalad", correctAnswer: "B", rationale: "The AP axial clavicle uses 15-30 degrees cephalad tube angle to project the clavicle above the thoracic cage, providing a clearer view of the clavicle free from rib superimposition.", modality: "X-ray", bodyPart: "Shoulder", category: "Radiographic Procedures", difficulty: 2, topic: "Upper Extremity" },
    { question: "The Alexander method for AC joint evaluation involves:", optionA: "No weights", optionB: "Taking bilateral AP projections with and without weights to compare joint widening", optionC: "Lateral views only", optionD: "Oblique views only", correctAnswer: "B", rationale: "AC joint evaluation compares bilateral weighted and non-weighted AP views. Abnormal widening of the AC joint space with weights suggests ligament injury. Both sides are imaged simultaneously for comparison.", modality: "X-ray", bodyPart: "Shoulder", category: "Radiographic Procedures", difficulty: 2, topic: "Upper Extremity" },
    { question: "The thumb (first digit) AP projection requires:", optionA: "PA projection", optionB: "True AP of the thumb, which requires rotating the hand into an extreme internal (medial) rotation", optionC: "Oblique only", optionD: "Lateral only", correctAnswer: "B", rationale: "A true AP thumb requires extreme internal rotation of the hand so the posterior surface of the thumb rests on the IR. This is opposite to the PA hand position and demonstrates the thumb's CMC, MCP, and IP joints.", modality: "X-ray", bodyPart: "Hand", category: "Radiographic Procedures", difficulty: 2, topic: "Upper Extremity" },
    { question: "For a lateral projection of the finger (2nd-5th digits), the finger is placed:", optionA: "Flat on the cassette", optionB: "In true lateral position with the adjacent fingers flexed away to prevent overlap", optionC: "In oblique position", optionD: "In PA position", correctAnswer: "B", rationale: "Lateral finger requires the digit in true lateral with adjacent fingers flexed away to prevent superimposition. The central ray is directed perpendicular to the PIP joint.", modality: "X-ray", bodyPart: "Hand", category: "Radiographic Procedures", difficulty: 1, topic: "Upper Extremity" },
    { question: "The PA oblique wrist in radial deviation best demonstrates:", optionA: "The ulnar side of the wrist", optionB: "The scaphoid bone elongated and without foreshortening", optionC: "The pisiform", optionD: "The distal radioulnar joint", correctAnswer: "B", rationale: "Ulnar deviation stretches the scaphoid, reducing overlap and foreshortening. Combined with slight elevation on the radial side, this is the dedicated scaphoid view used to evaluate suspected scaphoid fractures.", modality: "X-ray", bodyPart: "Wrist", category: "Radiographic Procedures", difficulty: 2, topic: "Upper Extremity" },
    { question: "For a lateral projection of the calcaneus, the central ray is directed:", optionA: "Through the ankle joint", optionB: "Perpendicular to the calcaneus (approximately 1 inch inferior to the medial malleolus)", optionC: "45 degrees cephalad", optionD: "To the toes", correctAnswer: "B", rationale: "The lateral calcaneus uses a perpendicular central ray entering approximately 1 inch inferior to the medial malleolus. The foot is dorsiflexed to demonstrate the subtalar joint and Böhler's angle.", modality: "X-ray", bodyPart: "Foot", category: "Radiographic Procedures", difficulty: 2, topic: "Lower Extremity" },
    { question: "Böhler's angle is measured on the lateral calcaneus and is normally:", optionA: "5-10 degrees", optionB: "28-40 degrees", optionC: "60-70 degrees", optionD: "0 degrees", correctAnswer: "B", rationale: "Böhler's angle (28-40 degrees normally) is formed by the intersection of two lines drawn on the lateral calcaneus. A flattened angle (<28 degrees) suggests a compression fracture of the calcaneus.", modality: "X-ray", bodyPart: "Foot", category: "Image Evaluation", difficulty: 3, topic: "Pathology" },
    { question: "The Stryker notch view of the shoulder demonstrates:", optionA: "The AC joint", optionB: "The posterolateral humeral head (Hill-Sachs defect) from recurrent anterior dislocation", optionC: "The scapula", optionD: "The clavicle", correctAnswer: "B", rationale: "The Stryker notch view (arm over head, 10-degree cephalad angle) demonstrates the posterolateral humeral head, where Hill-Sachs compression defects occur from recurrent anterior shoulder dislocations.", modality: "X-ray", bodyPart: "Shoulder", category: "Radiographic Procedures", difficulty: 3, topic: "Upper Extremity" },
    { question: "An inlet view of the pelvis uses:", optionA: "No tube angle", optionB: "40 degrees caudad to demonstrate the pelvic inlet (brim) for fracture displacement assessment", optionC: "40 degrees cephalad", optionD: "Lateral projection", correctAnswer: "B", rationale: "The pelvic inlet view (40 degrees caudad) demonstrates the pelvic brim (inlet), showing anterior-posterior displacement of pelvic ring fractures. It is part of the trauma pelvic series.", modality: "X-ray", bodyPart: "Pelvis", category: "Radiographic Procedures", difficulty: 3, topic: "Lower Extremity" },
    { question: "An outlet view of the pelvis uses:", optionA: "No tube angle", optionB: "40 degrees cephalad to demonstrate the pubic rami and ischial rami for vertical displacement", optionC: "40 degrees caudad", optionD: "Lateral projection", correctAnswer: "B", rationale: "The pelvic outlet view (40 degrees cephalad) demonstrates the pubic and ischial rami, showing superior-inferior (vertical) displacement of pelvic ring fractures. Used with inlet view for trauma.", modality: "X-ray", bodyPart: "Pelvis", category: "Radiographic Procedures", difficulty: 3, topic: "Lower Extremity" },
    { question: "For SC (sternoclavicular) joints, the best projection is:", optionA: "AP chest", optionB: "PA oblique (body rotated 10-15 degrees from PA) or PA with slight tube angle", optionC: "Lateral chest", optionD: "AP shoulder", correctAnswer: "B", rationale: "SC joints are best demonstrated by PA oblique (10-15 degrees rotation) to separate the joints from the spine, or PA with slight cephalad angle. This projects the joints free from vertebral body superimposition.", modality: "X-ray", bodyPart: "Sternum", category: "Radiographic Procedures", difficulty: 2, topic: "Thorax Radiography" },
    { question: "For an AP axial projection of the zygomatic arches, the tube is angled:", optionA: "Perpendicular", optionB: "30 degrees caudad (or SMV modification)", optionC: "15 degrees cephalad", optionD: "45 degrees cephalad", correctAnswer: "B", rationale: "The AP axial zygomatic arches (modified Towne) uses 30 degrees caudad angle to demonstrate both zygomatic arches simultaneously, projecting them free from overlying cranial structures.", modality: "X-ray", bodyPart: "Skull", category: "Radiographic Procedures", difficulty: 2, topic: "Skull Radiography" },
    { question: "For an oblique projection of the cervical spine to demonstrate intervertebral foramina:", optionA: "The patient is rotated 15 degrees", optionB: "The patient is rotated 45 degrees from the AP or PA position, with 15-20 degrees cephalad tube angle for AP oblique", optionC: "No rotation is needed", optionD: "The patient is rotated 90 degrees", correctAnswer: "B", rationale: "Cervical obliques require 45-degree rotation. AP oblique (RPO/LPO) with 15-20 degrees cephalad angle demonstrates the foramina farthest from the IR. PA oblique (RAO/LAO) with caudad angle shows the foramina nearest the IR.", modality: "X-ray", bodyPart: "Cervical Spine", category: "Radiographic Procedures", difficulty: 2, topic: "Spine Radiography" },
    { question: "The AP projection of the sacroiliac (SI) joints requires:", optionA: "Perpendicular CR", optionB: "25-30 degrees cephalad tube angle to open the SI joints", optionC: "30 degrees caudad", optionD: "Lateral position", correctAnswer: "B", rationale: "The AP axial SI joints uses 25-30 degrees cephalad tube angle to project the SI joints open, as they are oriented obliquely (about 25-30 degrees from sagittal plane).", modality: "X-ray", bodyPart: "Pelvis", category: "Radiographic Procedures", difficulty: 2, topic: "Lower Extremity" },
    { question: "The swimmer's lateral view is performed when:", optionA: "The patient is swimming", optionB: "The C7-T1 junction cannot be demonstrated on the standard lateral cervical spine due to shoulder overlap", optionC: "The patient has a shoulder injury", optionD: "For routine C-spine evaluation", correctAnswer: "B", rationale: "The swimmer's lateral (Twining method) is performed when C7-T1 is obscured by shoulder overlap. One arm is raised overhead, one is at the side, and the beam is directed horizontally through the cervicothoracic junction.", modality: "X-ray", bodyPart: "Cervical Spine", category: "Radiographic Procedures", difficulty: 2, topic: "Spine Radiography" },

    // ADDITIONAL MISCELLANEOUS
    { question: "The primary purpose of using a small focal spot is:", optionA: "To increase tube loading", optionB: "To improve spatial resolution and geometric sharpness", optionC: "To increase mAs capacity", optionD: "To reduce heat production", correctAnswer: "B", rationale: "Small focal spots produce less geometric unsharpness (penumbra), resulting in sharper images with better spatial resolution. They are used for extremities, magnification, and fine-detail work. Trade-off: reduced heat capacity.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 1, topic: "Image Quality" },
    { question: "The primary purpose of using a large focal spot is:", optionA: "To improve resolution", optionB: "To allow higher tube loading (higher mA) for thick body parts requiring more radiation output", optionC: "To reduce patient dose", optionD: "To improve contrast", correctAnswer: "B", rationale: "Large focal spots can handle higher mA settings because heat is spread over a larger area of the anode. Used for thick body parts (abdomen, pelvis, lateral spine) where high mAs is needed.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 1, topic: "Image Quality" },
    { question: "The Potter-Bucky diaphragm is:", optionA: "A filter", optionB: "A moving grid mechanism that oscillates the grid during exposure to blur the grid lines", optionC: "A fixed grid", optionD: "A collimator", correctAnswer: "B", rationale: "The Potter-Bucky (or Bucky) is a device that holds and moves the grid during exposure. The oscillating motion blurs the grid lines, making them invisible on the image while maintaining scatter cleanup.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "Grids" },
    { question: "Subject contrast in radiography depends on:", optionA: "Only kVp", optionB: "Atomic number, density, and thickness of body structures, plus beam energy (kVp)", optionC: "Only mAs", optionD: "Only the detector", correctAnswer: "B", rationale: "Subject contrast depends on: 1) Atomic number (Z) differences between tissues, 2) Density differences, 3) Thickness differences, and 4) Beam energy (kVp). Higher kVp reduces subject contrast.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "Image Quality" },
    { question: "ALARA stands for:", optionA: "Always Low And Reasonably Available", optionB: "As Low As Reasonably Achievable", optionC: "Always Low And Ready for Action", optionD: "As Long As Radiation is Appropriate", correctAnswer: "B", rationale: "ALARA (As Low As Reasonably Achievable) is the guiding principle for radiation protection. It means using the lowest radiation dose that still produces diagnostic-quality images.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 1, topic: "ALARA Principle" },
    { question: "The purpose of the ALARA principle is to:", optionA: "Maximize patient dose", optionB: "Minimize radiation exposure to patients, staff, and the public while maintaining diagnostic image quality", optionC: "Eliminate all radiation", optionD: "Increase exam throughput", correctAnswer: "B", rationale: "ALARA aims to keep all radiation exposures to the lowest level reasonably achievable while still obtaining the diagnostic information needed for patient care.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 1, topic: "ALARA Principle" },
    { question: "In digital radiography, overexposure results in:", optionA: "A dark, unacceptable image", optionB: "An acceptable-looking image but with unnecessary patient dose (exposure creep risk)", optionC: "Equipment damage", optionD: "Immediate image deletion", correctAnswer: "B", rationale: "Due to the wide dynamic range of digital detectors, overexposure produces images that may look acceptable (or even good). This is the basis of 'exposure creep' — gradual increase in technique without visible consequence but with increased patient dose.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "Digital Imaging" },
    { question: "In digital radiography, underexposure results in:", optionA: "An overly bright image", optionB: "Increased quantum noise (mottle) and degraded image quality", optionC: "Equipment damage", optionD: "No visible effect", correctAnswer: "B", rationale: "Underexposure means fewer photons reach the detector, increasing quantum noise (mottle). The image appears grainy, especially in uniform soft tissue areas. Severe underexposure may render the image non-diagnostic.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 1, topic: "Digital Imaging" },
    { question: "The standard SID for upright PA chest radiography is:", optionA: "40 inches (100 cm)", optionB: "72 inches (180 cm)", optionC: "36 inches (90 cm)", optionD: "60 inches (150 cm)", correctAnswer: "B", rationale: "PA chest uses 72-inch (180 cm) SID to minimize cardiac magnification. The increased distance reduces beam divergence, providing more accurate heart size assessment. Cardiac magnification should be <5%.", modality: "X-ray", bodyPart: "Chest", category: "Radiographic Procedures", difficulty: 1, topic: "Chest Radiography" },
    { question: "The term 'technique chart' refers to:", optionA: "A patient positioning guide", optionB: "A standardized chart listing recommended kVp, mAs, SID, and grid use for each body part and projection", optionC: "An equipment maintenance schedule", optionD: "A radiation dose record", correctAnswer: "B", rationale: "Technique charts provide standardized exposure factors for each projection based on body part thickness. They ensure consistent image quality, reduce repeat rates, and are required by most radiation safety regulations.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 1, topic: "Exposure Factors" },
    { question: "Body habitus affects radiographic positioning because:", optionA: "It does not affect positioning", optionB: "Different body types (sthenic, asthenic, hypersthenic, hyposthenic) have organs at different positions, requiring adjustments in centering and field size", optionC: "Only the weight matters", optionD: "Only height matters", correctAnswer: "B", rationale: "Hypersthenic patients have high, horizontal organs (gallbladder lateral, stomach horizontal, large colon). Asthenic patients have low, vertical organs. Centering points, field sizes, and technique must be adjusted accordingly.", modality: "X-ray", bodyPart: "General", category: "Radiographic Procedures", difficulty: 2, topic: "General Principles" },
    { question: "The AP projection differs from the PA projection in that:", optionA: "They are the same", optionB: "AP: beam enters anteriorly and exits posteriorly. PA: beam enters posteriorly and exits anteriorly (patient facing the IR)", optionC: "AP uses higher kVp", optionD: "PA uses more mAs", correctAnswer: "B", rationale: "AP = beam enters the anterior surface first (patient supine or facing the tube). PA = beam enters the posterior surface first (patient facing the IR). PA reduces dose to radiosensitive anterior organs and minimizes cardiac magnification.", modality: "X-ray", bodyPart: "General", category: "Radiographic Procedures", difficulty: 1, topic: "General Principles" },
  ];

  qs.push(...moreQuestions);
  return qs;
}

export function generateBulkQuestions3(): CamrtQuestion[] {
  const qs: CamrtQuestion[] = [];

  // Generate systematic variations across domains to reach 800 total
  const topicVariations: CamrtQuestion[] = [
    // PATIENT CARE - Additional
    { question: "A moderate contrast reaction includes:", optionA: "Only warmth", optionB: "Diffuse urticaria, mild bronchospasm, facial edema, or tachycardia", optionC: "Cardiac arrest", optionD: "Only metallic taste", correctAnswer: "B", rationale: "Moderate reactions include diffuse urticaria/hives, facial or laryngeal edema without dyspnea, mild bronchospasm (wheezing), tachycardia, and hypertension. They require treatment and monitoring.", modality: "CT", bodyPart: "General", category: "Patient Care", difficulty: 2, topic: "Venipuncture & Contrast Media" },
    { question: "Metformin should be held after iodinated contrast administration because:", optionA: "It causes allergic reactions", optionB: "If contrast-induced nephropathy occurs, metformin accumulation can cause lactic acidosis", optionC: "It interferes with image quality", optionD: "It increases contrast viscosity", correctAnswer: "B", rationale: "Metformin is renally excreted. If contrast causes nephropathy, metformin accumulates, potentially causing fatal lactic acidosis. Metformin is typically held for 48 hours post-contrast, with renal function checked before resuming.", modality: "CT", bodyPart: "General", category: "Patient Care", difficulty: 3, topic: "Venipuncture & Contrast Media" },
    { question: "The universal sign of choking is:", optionA: "Coughing loudly", optionB: "Hands clutching the throat", optionC: "Falling down", optionD: "Vomiting", correctAnswer: "B", rationale: "The universal sign for choking is hands clutching the throat. If the patient cannot speak, cough, or breathe, perform the Heimlich maneuver (abdominal thrusts) to dislodge the obstruction.", modality: "General", bodyPart: "General", category: "Patient Care", difficulty: 1, topic: "Medical Emergencies" },
    { question: "The proper technique for using a pulse oximeter includes:", optionA: "Placing it on any finger with nail polish", optionB: "Placing on a clean, warm finger free of nail polish, with good peripheral perfusion", optionC: "Placing on the earlobe only", optionD: "No specific technique needed", correctAnswer: "B", rationale: "Pulse oximeters measure SpO2 using light absorption. Nail polish, poor perfusion, hypothermia, and motion can cause inaccurate readings. Normal SpO2 is 95-100%.", modality: "General", bodyPart: "General", category: "Patient Care", difficulty: 1, topic: "Vital Signs" },
    { question: "The medical abbreviation 'NPO' means:", optionA: "No photographs only", optionB: "Nothing by mouth (nil per os)", optionC: "Normal procedure ordered", optionD: "No previous orders", correctAnswer: "B", rationale: "NPO (nil per os) means nothing by mouth. Patients are NPO before procedures requiring fasting (contrast studies, sedation, surgery) to reduce aspiration risk.", modality: "General", bodyPart: "General", category: "Patient Care", difficulty: 1, topic: "Medical Terminology" },
    { question: "A written incident report should be filed when:", optionA: "Only when asked by management", optionB: "Whenever a patient fall, contrast reaction, wrong-patient exam, or any safety event occurs", optionC: "Only for fatal events", optionD: "Only for equipment malfunction", correctAnswer: "B", rationale: "Incident reports document any event that could compromise patient safety: falls, contrast reactions, wrong-patient or wrong-exam errors, equipment failures, radiation overexposures, and near-misses.", modality: "General", bodyPart: "General", category: "Patient Care", difficulty: 1, topic: "Patient Safety" },
    { question: "When a patient arrives with IV fluids running, the technologist should:", optionA: "Disconnect the IV", optionB: "Verify the IV is running properly, keep the bag above the IV site, and work around the IV during positioning", optionC: "Stop the infusion", optionD: "Remove the IV catheter", correctAnswer: "B", rationale: "IV fluids should continue uninterrupted. Ensure the IV is patent (flowing), keep the bag above the venipuncture site to prevent backflow, and position carefully to avoid kinking or dislodging the line.", modality: "General", bodyPart: "General", category: "Patient Care", difficulty: 1, topic: "Patient Care Procedures" },
    { question: "Nosocomial infection refers to:", optionA: "Community-acquired infection", optionB: "Healthcare-associated infection acquired during hospitalization", optionC: "Childhood illness", optionD: "Seasonal influenza", correctAnswer: "B", rationale: "Nosocomial (healthcare-associated) infections are acquired in a healthcare facility and were not present at admission. Common examples include MRSA, VRE, C. difficile, catheter-related UTI, and ventilator-associated pneumonia.", modality: "General", bodyPart: "General", category: "Patient Care", difficulty: 1, topic: "Infection Control" },
    { question: "The correct body mechanics for lifting a patient include:", optionA: "Bending at the waist", optionB: "Bending at the knees, keeping the back straight, lifting with the legs, and holding the load close to the body", optionC: "Twisting while lifting", optionD: "Lifting with the arms extended", correctAnswer: "B", rationale: "Proper body mechanics prevent technologist injury: bend at knees (not waist), keep back straight, lift with leg muscles, hold the load close, avoid twisting, and use a wide base of support.", modality: "General", bodyPart: "General", category: "Patient Care", difficulty: 1, topic: "Patient Transfer" },
    { question: "The medical term for difficulty swallowing is:", optionA: "Dyspnea", optionB: "Dysphagia", optionC: "Dysuria", optionD: "Diplopia", correctAnswer: "B", rationale: "Dysphagia = difficulty swallowing (important for barium swallow studies). Dyspnea = difficulty breathing. Dysuria = painful urination. Diplopia = double vision.", modality: "General", bodyPart: "General", category: "Patient Care", difficulty: 1, topic: "Medical Terminology" },

    // RADIATION PROTECTION - Additional
    { question: "Half-life refers to:", optionA: "Patient dose", optionB: "The time required for a radioactive substance to decay to half its original activity", optionC: "Equipment lifespan", optionD: "Image display time", correctAnswer: "B", rationale: "Physical half-life is the time for a radioactive material to decay to 50% of its activity. For example, Tc-99m has a physical half-life of 6 hours. After one half-life, activity is 50%; after two, 25%.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 2, topic: "Nuclear Physics" },
    { question: "The annual dose limit for the general public in Canada is:", optionA: "50 mSv", optionB: "1 mSv", optionC: "5 mSv", optionD: "20 mSv", correctAnswer: "B", rationale: "The CNSC limits public (non-occupational) effective dose to 1 mSv per year from regulated activities. This is one-fiftieth of the occupational limit (50 mSv), reflecting the lower acceptable risk for the public.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 2, topic: "Dose Limits" },
    { question: "Pair production occurs at photon energies above:", optionA: "70 keV", optionB: "1.02 MeV", optionC: "100 keV", optionD: "500 keV", correctAnswer: "B", rationale: "Pair production requires photon energy > 1.02 MeV (rest mass energy of electron-positron pair). It does not occur at diagnostic x-ray energies and is primarily relevant in radiation therapy.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 3, topic: "X-ray Interactions" },
    { question: "The occupancy factor (T) in shielding calculations represents:", optionA: "The time the tube is in use", optionB: "The fraction of time an area is occupied by persons", optionC: "The tube current", optionD: "The temperature", correctAnswer: "B", rationale: "Occupancy factor T represents the fraction of time an area is expected to be occupied. Full occupancy (T=1): offices, waiting rooms. Partial (T=1/4): corridors. Low (T=1/16): restrooms, stairwells.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 2, topic: "Structural Shielding" },
    { question: "The use factor (U) in shielding calculations represents:", optionA: "The distance from the tube", optionB: "The fraction of time the primary beam is directed toward a specific barrier", optionC: "The patient's body mass", optionD: "The image quality", correctAnswer: "B", rationale: "Use factor U represents the fraction of workload during which the primary beam is directed at a specific barrier. Floor: U=1 (always directed down). Walls: U varies (typically 1/4). Ceiling: variable.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 3, topic: "Structural Shielding" },
    { question: "The effect of distance on radiation exposure follows:", optionA: "The direct proportion law", optionB: "The inverse square law — doubling distance reduces intensity to one-quarter", optionC: "No relationship exists", optionD: "A linear relationship", correctAnswer: "B", rationale: "The inverse square law states intensity is inversely proportional to the square of the distance. Doubling distance from 1m to 2m reduces intensity to 1/4. This is a key radiation protection tool.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 1, topic: "Inverse Square Law" },
    { question: "Radiation hormesis is the theory that:", optionA: "All radiation is harmful", optionB: "Small doses of radiation may be beneficial by stimulating cellular repair mechanisms", optionC: "Radiation has no effect", optionD: "High doses are safe", correctAnswer: "B", rationale: "Radiation hormesis proposes that very low radiation doses may stimulate adaptive repair responses, potentially reducing cancer risk. This remains controversial; regulatory standards still use the LNT model.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 3, topic: "Radiation Biology" },
    { question: "Coherent (classical) scattering:", optionA: "Is the most common interaction in diagnostic radiology", optionB: "Changes photon direction without energy transfer or ionization, contributing minimally to image formation", optionC: "Produces scatter and contrast", optionD: "Is the same as photoelectric", correctAnswer: "B", rationale: "Coherent (classical/Rayleigh) scatter changes photon direction without energy loss. It is a relatively unimportant interaction in diagnostic radiology, occurring mainly at low energies.", modality: "General", bodyPart: "General", category: "Radiation Protection", difficulty: 3, topic: "X-ray Interactions" },

    // IMAGE PRODUCTION - Additional
    { question: "The density maintenance formula when changing SID is:", optionA: "mAs₁ = mAs₂", optionB: "mAs₁/mAs₂ = SID₁²/SID₂²", optionC: "mAs₁ × SID₁ = mAs₂ × SID₂", optionD: "Not related", correctAnswer: "B", rationale: "To maintain receptor exposure when SID changes: new mAs = old mAs × (new SID²/old SID²). Example: changing from 40 to 72 inches: mAs factor = (72/40)² = 3.24 times more mAs.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "Exposure Factors" },
    { question: "Object-to-image distance (OID) should be:", optionA: "Maximized for best resolution", optionB: "Minimized to reduce magnification and geometric unsharpness", optionC: "Maximum at all times", optionD: "Not considered in positioning", correctAnswer: "B", rationale: "Minimizing OID (placing the body part as close to the IR as possible) reduces magnification and geometric unsharpness. PA chest and PA hand positions inherently minimize OID for the structures of interest.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 1, topic: "Image Quality" },
    { question: "Beam hardening occurs when:", optionA: "The beam is softened", optionB: "Low-energy photons are preferentially absorbed by filtration or tissue, increasing average beam energy", optionC: "kVp is decreased", optionD: "mAs is increased", correctAnswer: "B", rationale: "Beam hardening is the selective removal of low-energy photons as the beam passes through material (filtration or patient tissue). The remaining beam has a higher average energy. This is the basis of beam filtration.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "X-ray Physics" },
    { question: "Dual-energy subtraction in digital radiography:", optionA: "Uses two different SIDs", optionB: "Acquires images at two different kVp settings and subtracts to separate bone and soft tissue", optionC: "Uses two detectors simultaneously", optionD: "Uses two different mAs", correctAnswer: "B", rationale: "Dual-energy subtraction acquires images at two kVp levels. By exploiting the different attenuation characteristics of bone and soft tissue at different energies, bone-only or soft-tissue-only images can be created.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 3, topic: "Digital Imaging" },
    { question: "The Hurter and Driffield (H&D) curve represents:", optionA: "Digital image processing", optionB: "The relationship between log exposure and optical density in film-screen radiography", optionC: "Patient dose vs image quality", optionD: "kVp vs mAs", correctAnswer: "B", rationale: "The H&D (characteristic) curve shows how film density changes with exposure. It has toe (underexposure), straight-line (useful range), and shoulder (overexposure) regions. Speed point and gamma describe film characteristics.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "Film-Screen Imaging" },
    { question: "Aliasing artifact in digital imaging occurs when:", optionA: "The patient moves", optionB: "The spatial frequency of the object exceeds the Nyquist frequency of the detector", optionC: "kVp is too high", optionD: "mAs is too low", correctAnswer: "B", rationale: "Aliasing (Moiré) occurs when spatial frequencies in the image exceed the detector's Nyquist frequency (1/2 pixel size). The detector cannot accurately represent these high frequencies, creating false patterns.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 3, topic: "Digital Imaging" },
    { question: "The purpose of image subtraction in digital imaging is:", optionA: "To increase noise", optionB: "To remove overlying anatomy and enhance visualization of contrast-filled structures", optionC: "To increase patient dose", optionD: "To blur the image", correctAnswer: "B", rationale: "Digital subtraction (e.g., DSA) subtracts a pre-contrast mask image from post-contrast images, removing overlying bone and soft tissue to demonstrate only the contrast-enhanced vessels or structures.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "Digital Imaging" },
    { question: "Image stitching artifacts can be minimized by:", optionA: "Using maximum collimation", optionB: "Ensuring adequate overlap between adjacent exposures and consistent technique", optionC: "Using a grid for each exposure", optionD: "Changing kVp between exposures", correctAnswer: "B", rationale: "Image stitching requires sufficient overlap between adjacent images (typically 2-3 cm), consistent exposure technique across all images, and precise patient positioning to prevent misalignment.", modality: "X-ray", bodyPart: "General", category: "Image Production", difficulty: 2, topic: "Digital Imaging" },

    // IMAGE EVALUATION - Additional
    { question: "On an AP projection of the foot, the metatarsal bases should appear:", optionA: "Overlapping significantly", optionB: "Separated with visible joint spaces between them", optionC: "Not visible", optionD: "Superimposed", correctAnswer: "B", rationale: "On a properly positioned AP foot with correct tube angle (10-15 degrees posterior), the tarsometatarsal joints and intermetatarsal spaces should be visible, with minimal overlap of the metatarsal bases.", modality: "X-ray", bodyPart: "Foot", category: "Image Evaluation", difficulty: 2, topic: "Image Critique" },
    { question: "On a properly positioned oblique foot, the space between the 3rd-5th metatarsal bases should be:", optionA: "Closed", optionB: "Open and clearly demonstrated without superimposition", optionC: "Overlapping", optionD: "Not visible", correctAnswer: "B", rationale: "The AP oblique foot (30-40 degrees medial rotation) opens the spaces between the 3rd-5th metatarsal bases and demonstrates the cuboid and lateral cuneiform relationships without superimposition.", modality: "X-ray", bodyPart: "Foot", category: "Image Evaluation", difficulty: 2, topic: "Image Critique" },
    { question: "Ghost artifacts in panoramic (panorex) dental imaging are caused by:", optionA: "Patient breathing", optionB: "Dense objects (earrings, spine) on the opposite side being projected as a blurred duplicate", optionC: "Film processing errors", optionD: "Incorrect kVp", correctAnswer: "B", rationale: "In panoramic radiography, dense objects (earrings, cervical spine, hyoid bone) on the opposite side of the rotating beam create ghost images — blurred, magnified, and projected on the opposite side and above.", modality: "X-ray", bodyPart: "Skull", category: "Image Evaluation", difficulty: 2, topic: "Artifacts" },
    { question: "Proper evaluation of an AP hand radiograph includes:", optionA: "Only checking density", optionB: "All phalanges, metacarpals, and carpals demonstrated with open joint spaces, no overlap, and proper density", optionC: "Only checking the fingers", optionD: "Only checking the wrist", correctAnswer: "B", rationale: "AP/PA hand evaluation: all 5 digits with open IP and MCP joints, metacarpals without overlap, carpals visible, adequate soft tissue visualization, proper exposure, and no rotation (equal soft tissue bilaterally).", modality: "X-ray", bodyPart: "Hand", category: "Image Evaluation", difficulty: 1, topic: "Image Critique" },
    { question: "On a properly positioned lateral elbow, which fat pad is normally visible?", optionA: "The posterior fat pad", optionB: "The anterior fat pad (small, thin stripe)", optionC: "Both fat pads equally", optionD: "Neither fat pad", correctAnswer: "B", rationale: "The anterior fat pad is normally visible as a small, thin stripe on the lateral elbow. The posterior fat pad is NOT normally visible. When the posterior fat pad is visible (sail sign), it indicates joint effusion, often from an occult fracture.", modality: "X-ray", bodyPart: "Elbow", category: "Image Evaluation", difficulty: 2, topic: "Image Critique" },
    { question: "Computed radiography (CR) cassettes should be erased:", optionA: "Never", optionB: "If not used within 48 hours or before each use to remove residual image data", optionC: "Only when damaged", optionD: "Only once per month", correctAnswer: "B", rationale: "CR cassettes should be erased before use if they have been idle for >48 hours, as environmental radiation and cosmic rays can add noise. Regular erasure ensures a clean latent image for each exposure.", modality: "X-ray", bodyPart: "General", category: "Image Evaluation", difficulty: 2, topic: "Quality Control" },

    // RADIOGRAPHIC PROCEDURES - Additional
    { question: "The Settegast method for the patella demonstrates:", optionA: "The knee in AP", optionB: "The patellofemoral joint in axial (tangential) projection with the patient prone and knee flexed", optionC: "The tibial plateau", optionD: "The fibular head", correctAnswer: "B", rationale: "The Settegast method demonstrates the patella in axial projection with the patient prone, knee flexed, and beam directed through the patellofemoral joint. It demonstrates tracking and articular surface.", modality: "X-ray", bodyPart: "Knee", category: "Radiographic Procedures", difficulty: 2, topic: "Lower Extremity" },
    { question: "For a lateral projection of the sternum, the SID should be:", optionA: "40 inches", optionB: "72 inches to reduce magnification due to the sternum's distance from the IR", optionC: "36 inches", optionD: "30 inches", correctAnswer: "B", rationale: "The lateral sternum uses 72-inch SID because the sternum is anterior and far from the IR in the lateral position. Increased SID reduces magnification, similar to the PA chest rationale.", modality: "X-ray", bodyPart: "Sternum", category: "Radiographic Procedures", difficulty: 2, topic: "Thorax Radiography" },
    { question: "An AP projection of ribs below the diaphragm requires exposure on:", optionA: "Full inspiration", optionB: "Expiration to push the diaphragm upward and demonstrate the lower ribs below it", optionC: "Any phase", optionD: "Full inspiration only", correctAnswer: "B", rationale: "Lower rib radiographs (below the diaphragm) are taken on expiration, which elevates the diaphragm and pushes it above the lower ribs, demonstrating ribs 8-12 below the diaphragm.", modality: "X-ray", bodyPart: "Ribs", category: "Radiographic Procedures", difficulty: 2, topic: "Thorax Radiography" },
    { question: "The Norgaard (ball-catcher's) projection of the hands requires the hands positioned:", optionA: "PA flat on the cassette", optionB: "In semi-supinated 45-degree oblique (as if holding a ball), both hands on the same cassette", optionC: "Lateral", optionD: "Fully supinated", correctAnswer: "B", rationale: "The Norgaard view positions both hands in 45-degree semi-supination (as if holding a large ball) on the same cassette. This demonstrates early erosive changes of rheumatoid arthritis at the MCP and PIP joints.", modality: "X-ray", bodyPart: "Hand", category: "Radiographic Procedures", difficulty: 3, topic: "Upper Extremity" },
    { question: "The AP projection of the acromioclavicular (AC) joints is typically performed:", optionA: "Unilateral only", optionB: "Bilateral (both AC joints on one image) with and without weights for comparison", optionC: "With the patient prone", optionD: "Lateral only", correctAnswer: "B", rationale: "AC joint evaluation requires bilateral comparison. Both joints are imaged simultaneously on one or two images, with and without weights. Abnormal widening with weights indicates AC ligament injury.", modality: "X-ray", bodyPart: "Shoulder", category: "Radiographic Procedures", difficulty: 2, topic: "Upper Extremity" },
    { question: "The lateral decubitus position is defined as:", optionA: "Patient standing sideways", optionB: "Patient lying on their side on the table with a horizontal (cross-table) beam", optionC: "Patient prone", optionD: "Patient supine with the tube angled", correctAnswer: "B", rationale: "Lateral decubitus = patient on their side with a horizontal beam. Named for the side the patient lies on: left lateral decubitus = lying on left side. Used to detect air-fluid levels and free air.", modality: "X-ray", bodyPart: "General", category: "Radiographic Procedures", difficulty: 1, topic: "General Principles" },
    { question: "For a swimmer's lateral, the arm nearest the IR should be:", optionA: "Raised overhead", optionB: "Depressed (at the side or pulled down), while the arm farthest from the IR is raised overhead", optionC: "Behind the back", optionD: "Both arms at the sides", correctAnswer: "B", rationale: "In the swimmer's lateral, the arm nearest the IR is depressed and the opposite arm is elevated overhead. This separates the shoulders to demonstrate the C7-T1 (cervicothoracic) junction.", modality: "X-ray", bodyPart: "Cervical Spine", category: "Radiographic Procedures", difficulty: 2, topic: "Spine Radiography" },
    { question: "An AP projection of the thoracic spine demonstrates:", optionA: "Only T1-T6", optionB: "T1-T12 vertebral bodies, disc spaces, pedicles, and spinous processes", optionC: "Only the lumbar spine", optionD: "Only the cervical spine", correctAnswer: "B", rationale: "AP thoracic spine demonstrates all 12 thoracic vertebrae, intervertebral disc spaces, pedicles, spinous processes, transverse processes, costovertebral and costotransverse joints.", modality: "X-ray", bodyPart: "Thoracic Spine", category: "Radiographic Procedures", difficulty: 1, topic: "Spine Radiography" },
    { question: "For a lateral projection of the thoracic spine, the arms should be:", optionA: "At the sides", optionB: "Raised above the head or positioned forward (90-degree flexion) to move the scapulae laterally", optionC: "Behind the back", optionD: "Crossed over the chest", correctAnswer: "B", rationale: "The arms are raised or flexed forward to move the scapulae laterally and anteriorly, clearing them from the thoracic vertebral bodies. A breathing technique (low mA, long time) blurs overlying ribs and lung.", modality: "X-ray", bodyPart: "Thoracic Spine", category: "Radiographic Procedures", difficulty: 1, topic: "Spine Radiography" },
    { question: "An AP axial (Towne) projection of the skull uses which tube angle?", optionA: "15 degrees caudad", optionB: "30 degrees caudad to the OML (or 37 degrees to IOML)", optionC: "45 degrees cephalad", optionD: "Perpendicular", correctAnswer: "B", rationale: "The Towne projection uses 30 degrees caudad angle to the OML (or 37 degrees to the IOML), projecting the occipital bone, foramen magnum, dorsum sellae, and posterior clinoid processes.", modality: "X-ray", bodyPart: "Skull", category: "Radiographic Procedures", difficulty: 2, topic: "Skull Radiography" },
    { question: "The horizontal beam lateral abdomen (dorsal decubitus) is used to:", optionA: "Demonstrate kidney stones", optionB: "Detect air-fluid levels and free air in patients who cannot sit or stand upright", optionC: "Show the spine only", optionD: "Demonstrate the bladder", correctAnswer: "B", rationale: "The dorsal decubitus (supine with horizontal beam lateral) demonstrates air-fluid levels and free air when the patient cannot sit upright. Left lateral decubitus is preferred for detecting free air (it rises to right side against liver).", modality: "X-ray", bodyPart: "Abdomen", category: "Radiographic Procedures", difficulty: 2, topic: "Abdominal Radiography" },
    { question: "For a PA projection of the chest, the patient's hands should be placed:", optionA: "At the sides", optionB: "On the hips with palms out and shoulders rolled forward to rotate scapulae laterally", optionC: "Above the head", optionD: "Behind the back", correctAnswer: "B", rationale: "Placing backs of hands on hips (low on the hips) and rolling shoulders forward and inward rotates the scapulae laterally, clearing them from the lung fields for better pulmonary evaluation.", modality: "X-ray", bodyPart: "Chest", category: "Radiographic Procedures", difficulty: 1, topic: "Chest Radiography" },
    { question: "The exposure for a PA chest should be made:", optionA: "During expiration", optionB: "After the second full inspiration (at peak inspiration) and with suspended respiration", optionC: "During breathing", optionD: "At any time", correctAnswer: "B", rationale: "PA chest should be exposed at peak inspiration (after the patient takes two deep breaths and holds on the second) to fully expand the lungs and separate structures. Motion is eliminated by suspending respiration.", modality: "X-ray", bodyPart: "Chest", category: "Radiographic Procedures", difficulty: 1, topic: "Chest Radiography" },
    { question: "For an AP supine abdomen on a large patient, adjustments may include:", optionA: "No adjustments needed", optionB: "Increasing mAs (higher technique), using two separate images (upper and lower), and ensuring adequate field coverage", optionC: "Decreasing kVp only", optionD: "Using a smaller cassette", correctAnswer: "B", rationale: "Large patients require: increased mAs for adequate penetration, possibly increased kVp, larger field of view, and sometimes two images (upper and lower abdomen) to include all anatomy from diaphragm to symphysis.", modality: "X-ray", bodyPart: "Abdomen", category: "Radiographic Procedures", difficulty: 2, topic: "Abdominal Radiography" },
    { question: "For the inferosuperior (Lawrence) axillary shoulder projection, the patient is:", optionA: "Prone", optionB: "Supine with the arm abducted and the beam directed through the axilla from below", optionC: "Standing", optionD: "Seated upright", correctAnswer: "B", rationale: "The Lawrence method positions the patient supine with the arm abducted 90 degrees. The central ray enters the axilla from the inferior surface, directed superiorly to the IR placed above the shoulder.", modality: "X-ray", bodyPart: "Shoulder", category: "Radiographic Procedures", difficulty: 2, topic: "Upper Extremity" },
    { question: "An AP projection of the mandible with the CR angled 20-25 degrees cephalad demonstrates:", optionA: "The frontal sinuses", optionB: "The mandibular body and mentum projected above the cervical spine", optionC: "The zygomatic arches", optionD: "The orbits", correctAnswer: "B", rationale: "The AP axial mandible uses 20-25 degrees cephalad angle to project the mandibular body and mentum superiorly above the cervical spine, demonstrating the mandibular body and symphysis.", modality: "X-ray", bodyPart: "Skull", category: "Radiographic Procedures", difficulty: 2, topic: "Skull Radiography" },
    { question: "A modified Waters (parietoacanthial) view with the mouth open demonstrates:", optionA: "The frontal sinuses only", optionB: "The sphenoid sinus seen through the open mouth", optionC: "The ethmoid sinuses only", optionD: "The maxillary sinuses only", correctAnswer: "B", rationale: "The modified Waters with mouth open demonstrates the sphenoid sinus through the open mouth, in addition to the maxillary sinuses above the petrous ridges. The open mouth provides a window to the sphenoid.", modality: "X-ray", bodyPart: "Sinuses", category: "Radiographic Procedures", difficulty: 2, topic: "Skull Radiography" },
    { question: "For a lateral scoliosis series, the patient should be:", optionA: "Supine", optionB: "Erect (standing) for weight-bearing assessment with the entire spine included on one long image", optionC: "Prone", optionD: "Lateral decubitus", correctAnswer: "B", rationale: "Scoliosis evaluation requires erect standing views to show the curve under weight-bearing conditions. PA projection is preferred to reduce breast/thyroid dose. Image stitching may be needed for full-spine coverage.", modality: "X-ray", bodyPart: "Spine", category: "Radiographic Procedures", difficulty: 2, topic: "Spine Radiography" },
    { question: "The Cobb angle is used to measure:", optionA: "Tube angle", optionB: "The degree of spinal curvature in scoliosis", optionC: "Patient rotation", optionD: "Grid angle", correctAnswer: "B", rationale: "The Cobb angle measures scoliosis severity by drawing lines along the superior endplate of the upper end vertebra and inferior endplate of the lower end vertebra, then measuring the angle between perpendiculars to these lines.", modality: "X-ray", bodyPart: "Spine", category: "Image Evaluation", difficulty: 3, topic: "Pathology" },
  ];

  qs.push(...topicVariations);
  return qs;
}

